// Automatically extracted from Python static/index.html

export const GUIDE_HTML_CONTENT: Record<string, string> = {
  "theme1": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 1</div>\n    <div class=\"panel-title\">La Paie et la Fiscalité Sociale</div>\n    <p class=\"panel-text\">La paie algérienne suit une cascade rigoureuse : construction du brut, identification des éléments cotisables, calcul de la CNAS salariale (9 %), puis application du barème IRG progressif après abattement de 40 %. Toute erreur dans la séquence génère un manquement fiscal ou social.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> CIDTA Art. 104 (LF 2022 → LF 2025) · Ord. n°95-01 Art. 1 · Loi n°83-11 Art. 52 · Décret n°06-373 du 18/10/2006 · LF 2024 · Circulaire DGI n°01/MF/DGI/2014</div>\n  </div>\n\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Cascade de calcul</div>\n    <div class=\"panel-title\">Du brut au net — séquence légale</div>\n    <div class=\"formula-grid\">\n      <div class=\"formula\"><strong>① Total gains bruts</strong><span>SB réel + IEP + primes mensuelles (nuisance, poste, nuit…) + HS + ICR + primes fixes + avantages en nature cotisables.</span></div>\n      <div class=\"formula\"><strong>② Base CNAS salariale</strong><span>Total brut − éléments non cotisables (panier, transport, frais de mission justifiés, prestations familiales). Réf. : Ord. n°95-01, Art. 1.</span></div>\n      <div class=\"formula\"><strong>③ CNAS salariale (9 %)</strong><span>Base CNAS × 9 %. Loi n°83-11, Art. 52. Reversée à la CNAS avant le 15 du mois suivant.</span></div>\n      <div class=\"formula\"><strong>④ Base IRG imposable</strong><span>Total brut − CNAS salariale − éléments exonérés d'IRG (Art. 68 CIDTA : allocations familiales, indemnités AT/MP légales, frais mission justifiés).</span></div>\n      <div class=\"formula\"><strong>⑤ Seuil d'exonération</strong><span>Si base IRG ≤ 30 000 DA → IRG = 0. Art. 104-3 CIDTA (LF 2022 → LF 2025). Exonération totale IRG + CNAS pour bénéficiaires ANADE/ANGEM/CNAC (LF 2024).</span></div>\n      <div class=\"formula\"><strong>⑥ Barème progressif IRG</strong><span>6 tranches annuelles : 0 % (≤ 30 000 DA/mois) · 23 % (42 501–480 000) · 27 % (480–960 k) · 30 % (960 k–1,92 M) · 33 % (1,92–3,84 M) · 35 % (&gt;3,84 M). + 2e abattement dégressif entre 30 001 et 42 500 DA. Art. 104 CIDTA (LF 2025).</span></div>\n      <div class=\"formula\"><strong>⑦ Abattement 40 %</strong><span>40 % × IRG brut. Plancher 1 000 DA / Plafond 1 500 DA par mois. Art. 104 CIDTA + Circulaire DGI n°01/MF/DGI/2014.</span></div>\n      <div class=\"formula\"><strong>⑧ Net à payer</strong><span>Total gains − CNAS salariale − IRG net − autres retenues (mutuelle, avances, saisies).</span></div>\n    </div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>📊 Barème IRG — Traitements & Salaires — Art. 104 CIDTA</h3>\n      <div style=\"overflow-x:auto\">\n      <table class=\"irg-tbl\">\n        <thead><tr><th>Fraction du revenu imposable annuel (DA)</th><th>Taux</th></tr></thead>\n        <tbody>\n          <tr style=\"background:var(--su-50,#f0fdf4)\"><td>N'excède pas 240 000 DA</td><td><strong>0 %</strong></td></tr>\n          <tr><td>De 240 001 DA à 480 000 DA</td><td><strong>23 %</strong></td></tr>\n          <tr><td>De 480 001 DA à 960 000 DA</td><td><strong>27 %</strong></td></tr>\n          <tr><td>De 960 001 DA à 1 940 000 DA</td><td><strong>30 %</strong></td></tr>\n          <tr><td>De 1 940 001 DA à 3 840 000 DA</td><td><strong>33 %</strong></td></tr>\n          <tr><td>Supérieure à 3 840 000 DA</td><td><strong>35 %</strong></td></tr>\n        </tbody>\n      </table>\n      </div>\n      <div class=\"panel-note\" style=\"margin-top:10px\">\n        <strong>Cas particuliers :</strong><br>\n        • <strong>Revenu ≤ 30 000 DA/mois</strong> → Exonération totale d'IRG (Art. 68 CIDTA).<br>\n        • <strong>Revenu entre 30 001 et 42 500 DA/mois</strong> → Barème progressif + abattement 40 %, puis <strong>2e abattement</strong> selon formule DGI : IRG = IRG(1er abattement) × (93/61) − (81 213/41).<br>\n        • Abattement 40 % sur IRG brut : min <strong>1 000 DA/mois</strong> / max <strong>1 500 DA/mois</strong>.<br>\n        • Primes non mensuelles (gratification, 13e mois…) : taux libératoire <strong>10 %</strong> — Art. 104 CIDTA.\n      </div>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🛡️ Cotisations CNAS / CNR — Décret n°06-373</h3>\n      <table class=\"rate-tbl\">\n        <tr><td>Assurances sociales</td><td>1,50 % sal. + 13,00 % pat.</td></tr>\n        <tr><td>Accidents travail / MP</td><td>— + 1,25 % pat.</td></tr>\n        <tr><td>Retraite (CNR)</td><td>6,75 % sal. + 7,50 % pat.</td></tr>\n        <tr><td>Chômage (CNAC)</td><td>0,50 % sal. + 1,00 % pat.</td></tr>\n        <tr><td>Retraite anticipée</td><td>0,25 % sal. + 0,25 % pat.</td></tr>\n        <tr><td>Fonds œuvres sociales</td><td>— + 0,50 % pat.</td></tr>\n        <tr><td><strong>TOTAL</strong></td><td><strong>9 % sal. + 25 % pat. = 34 %</strong></td></tr>\n      </table>\n      <div class=\"panel-note\" style=\"margin-top:8px\">Réf. : Décret n°94-12 · Décret exécutif n°06-373 du 18/10/2006.</div>\n    </div>\n    <div class=\"rh-card\">\n      <h3>✅ Éléments cotisables CNAS (Ord. n°95-01, Art. 1)</h3>\n      <ul>\n        <li>Salaire de base réel et IEP (Indemnité d'Expérience Professionnelle).</li>\n        <li>Indemnités de poste, de nuisance, de nuit, de responsabilité.</li>\n        <li>Primes mensuelles de rendement, de caisse, de permanence.</li>\n        <li>Heures supplémentaires (majorées selon Art. 31 Loi 90-11).</li>\n        <li>ICR (Indemnité Complémentaire de Rémunération) et primes fixes.</li>\n        <li>Avantages en nature (évalués selon Décret n°96-24 ; cotisables à 2 % si &gt; SNMG).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>⛔ Éléments non cotisables CNAS (Ord. n°95-01, Art. 1 · Loi n°83-11, Art. 74)</h3>\n      <ul>\n        <li>Indemnités représentatives de frais : panier, transport, téléphone.</li>\n        <li>Frais de déplacement et de mission justifiés (Décret n°91-316).</li>\n        <li>Prestations à caractère familial (allocations familiales, PSU, scolarité).</li>\n        <li>Indemnités de résidence, d'isolement et de zone géographique.</li>\n        <li>Primes à caractère exceptionnel : innovation, expatriation.</li>\n        <li>Remboursements de frais réels sur justificatifs.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>💵 Seuils et indicateurs clés (2024)</h3>\n      <table class=\"rate-tbl\">\n        <tr><td>SNMG mensuel</td><td><strong>24 000 DA</strong> — Décret n°23-411 du 28/12/2023</td></tr>\n        <tr><td>Seuil exonération IRG</td><td><strong>30 000 DA/mois</strong> — Art. 104-3 CIDTA</td></tr>\n        <tr><td>Abattement IRG min</td><td><strong>1 000 DA/mois</strong> — Art. 104 CIDTA</td></tr>\n        <tr><td>Abattement IRG max</td><td><strong>1 500 DA/mois</strong> — Art. 104 CIDTA</td></tr>\n        <tr><td>Taux libératoire primes</td><td><strong>10 %</strong> — Art. 104 CIDTA</td></tr>\n        <tr><td>Exonération pension retraite</td><td><strong>≤ 20 000 DA/mois</strong> — Art. 68 CIDTA</td></tr>\n      </table>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📤 Obligations déclaratives employeur (paie)</h3>\n      <ul>\n        <li><strong>CNAS mensuelle :</strong> Cotisations versées avant le 15 du mois suivant. Bordereau ou téléservice CNAS.</li>\n        <li><strong>IRG retenu à la source :</strong> Versement mensuel à la DGI (calendrier fiscal DGI).</li>\n        <li><strong>DAS annuelle :</strong> Déclaration Annuelle des Salaires à la DGI avant le 30 avril (N+1).</li>\n        <li><strong>DAC annuelle :</strong> Déclaration Annuelle des Cotisations à la CNAS avant le 31 janvier (N+1). Réf. : Loi n°83-14.</li>\n        <li>Conserver preuves de paiement : quittances et accusés téléservice <strong>10 ans minimum</strong>.</li>\n      </ul>\n    </div>\n  </div>\n\n  <!-- Simulateur interactif -->\n  <div class=\"panel\" style=\"margin-top:16px\">\n    <div class=\"panel-kicker\">Outil interactif</div>\n    <div class=\"panel-title\">Simulateur de paie — du brut au net</div>\n    <p class=\"panel-text\">Saisissez la composition du salaire pour voir la cascade CNAS → IRG → Net se recalculer en temps réel. Le panier est non cotisable CNAS mais imposable IRG (CIDTA Art. 68).</p>\n    <style>\n      .sim-slider-row{display:flex;align-items:center;gap:12px;margin:10px 0}\n      .sim-slider-row label{font-size:12px;color:var(--muted);white-space:nowrap;min-width:220px;font-weight:600}\n      .sim-slider-row input[type=range]{flex:1}\n      .sim-slider-val{font-size:13px;font-weight:700;min-width:110px;text-align:right;color:var(--navy)}\n      .sim-num-row{display:flex;align-items:center;gap:12px;margin:6px 0}\n      .sim-num-row label{font-size:12px;color:var(--muted);white-space:nowrap;min-width:220px;font-weight:600}\n      .sim-num-row input[type=number]{width:120px;padding:4px 8px;font-size:13px;border:1px solid var(--line);border-radius:6px;background:var(--surface);color:var(--text);text-align:right}\n      .sim-badge{display:inline-block;padding:1px 7px;border-radius:10px;font-size:10px;font-weight:700;margin-left:6px}\n      .sim-badge-blue{background:var(--blue-lt);color:var(--blue)}\n      .sim-badge-amber{background:#fef3c7;color:#92400e}\n      .sim-section{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:var(--muted);margin:16px 0 6px;padding-bottom:4px;border-bottom:1px solid var(--line)}\n      .sim-cascade{display:flex;flex-direction:column;gap:0;margin-top:16px}\n      .sim-step{display:flex;align-items:stretch;gap:0}\n      .sim-bar{width:4px;flex-shrink:0;margin:0 16px;border-radius:2px}\n      .sim-bar-green  { background: var(--teal,   #0f6e56); }\n      .sim-bar-amber  { background: var(--amber,  #b45309); }\n      .sim-bar-red    { background: var(--red-600, #c23a28); }\n      .sim-bar-blue   { background: var(--accent, #2563a8); }\n      .sim-bar-gray   { background: var(--muted,  #6b7280); }\n      .sim-sc{flex:1;padding:10px 0 18px}\n      .sim-val{font-size:20px;font-weight:800;color:var(--navy);margin:0;font-variant-numeric:tabular-nums}\n      .sim-lbl{font-size:11px;color:var(--muted);margin:0 0 3px;font-weight:700;text-transform:uppercase;letter-spacing:.05em}\n      .sim-detail{font-size:11px;color:var(--muted);margin:3px 0 0;line-height:1.5}\n      .sim-tranches{width:100%;border-collapse:collapse;font-size:12px;margin:8px 0}\n      .sim-tranches td{padding:5px 8px;border-bottom:1px solid var(--line-soft)}\n      .sim-tranches td:last-child{text-align:right;font-weight:700}\n      .sim-tranches tr.s-active td{background:var(--blue-lt);color:var(--blue)}\n      .sim-tranches tr.s-zero td{color:var(--muted)}\n      .sim-tranches tfoot td{font-weight:700;border-top:1px solid var(--line);border-bottom:none;padding-top:8px}\n      .sim-abat{background:var(--surface);border:1px solid var(--line);border-radius:8px;padding:10px 14px;margin:8px 0;font-size:12px}\n      .sim-abat .r{display:flex;justify-content:space-between;margin:2px 0}\n      .sim-abat .r.total{font-weight:700;margin-top:6px;border-top:1px solid var(--line);padding-top:6px}\n      .sim-net{background:var(--teal-bg,#e8f7f3);border:2px solid var(--teal,#0f6e56);border-radius:10px;padding:14px 18px;margin-top:10px}\n      .sim-net .nl{font-size:11px;color:var(--teal-ink,#053d30);font-weight:800;text-transform:uppercase;letter-spacing:.05em;margin:0}\n      .sim-net .nv{font-size:26px;font-weight:800;color:var(--teal-ink,#053d30);margin:4px 0 0;font-variant-numeric:tabular-nums}\n      .sim-net .nd{font-size:11px;color:var(--teal,#0f6e56);margin:3px 0 0;font-variant-numeric:tabular-nums}\n      .badge-exo{display:inline-block;background:var(--teal-bg,#e8f7f3);color:var(--teal,#0f6e56);font-size:10px;padding:2px 8px;border-radius:10px;border:1px solid var(--teal-200,#9ed8c8);margin-left:6px;font-weight:700}\n      .sim-val-amber{color:var(--amber,#b45309)}\n      .sim-val-red{color:var(--red-600,#c23a28)}\n      .sim-cout{background:var(--amber-lt);border:1px solid var(--amber);border-radius:8px;padding:10px 14px;margin-top:8px;font-size:12px;display:flex;justify-content:space-between}\n      .sim-exo{background:var(--green-lt);border:1px solid var(--green);border-radius:8px;padding:10px 14px;margin-top:8px;font-size:12px;color:var(--green)}\n      .sim-note-panier{background:#fef9ec;border-left:3px solid #d97706;border-radius:0 6px 6px 0;padding:7px 12px;font-size:11px;color:#78350f;margin:8px 0}\n    </style>\n\n    <div class=\"sim-section\">Salaire de base</div>\n    <div class=\"sim-slider-row\">\n      <label for=\"g-brut\">Salaire de base théorique</label>\n      <input type=\"range\" id=\"g-brut\" min=\"24000\" max=\"300000\" step=\"1000\" value=\"100000\" oninput=\"guideRecalc()\">\n      <span class=\"sim-slider-val\" id=\"g-brut-lbl\">100 000 DA</span>\n    </div>\n\n    <div class=\"sim-section\">Primes en % du salaire de base réel</div>\n    <div class=\"sim-num-row\">\n      <label>I.E.P (ancienneté) %</label>\n      <input type=\"number\" id=\"g-iep\" value=\"0\" min=\"0\" max=\"20\" step=\"0.5\" oninput=\"guideRecalc()\">\n      <span class=\"sim-badge sim-badge-blue\">Cotisable / Imposable IRG</span>\n    </div>\n    <div class=\"sim-num-row\">\n      <label>Indemnité de nuisance %</label>\n      <input type=\"number\" id=\"g-nuis\" value=\"0\" min=\"0\" max=\"50\" step=\"0.5\" oninput=\"guideRecalc()\">\n      <span class=\"sim-badge sim-badge-blue\">Cotisable / Imposable IRG</span>\n    </div>\n    <div class=\"sim-num-row\">\n      <label>Prime de responsabilité %</label>\n      <input type=\"number\" id=\"g-resp\" value=\"0\" min=\"0\" max=\"100\" step=\"0.5\" oninput=\"guideRecalc()\">\n      <span class=\"sim-badge sim-badge-blue\">Cotisable / Imposable IRG</span>\n    </div>\n    <div class=\"sim-num-row\">\n      <label>Autres primes en % (P.R.I, P.R.C…)</label>\n      <input type=\"number\" id=\"g-autres-pct\" value=\"0\" min=\"0\" max=\"200\" step=\"0.5\" oninput=\"guideRecalc()\">\n      <span class=\"sim-badge sim-badge-blue\">Cotisable / Imposable IRG</span>\n    </div>\n\n    <div class=\"sim-section\">Primes et indemnités fixes</div>\n    <div class=\"sim-num-row\">\n      <label>I.C.R et primes fixes (DA)</label>\n      <input type=\"number\" id=\"g-icr\" value=\"0\" min=\"0\" step=\"100\" oninput=\"guideRecalc()\">\n      <span class=\"sim-badge sim-badge-blue\">Cotisable / Imposable IRG</span>\n    </div>\n    <div class=\"sim-slider-row\">\n      <label for=\"g-panier\">Panier (montant total mensuel)</label>\n      <input type=\"range\" id=\"g-panier\" min=\"0\" max=\"30000\" step=\"500\" value=\"0\" oninput=\"guideRecalc()\">\n      <span class=\"sim-slider-val\" id=\"g-panier-lbl\">0 DA</span>\n    </div>\n    <div class=\"sim-note-panier\">⚠ Le panier est <strong>non cotisable CNAS</strong> (Ord. n°95-01 Art. 1) mais reste <strong>imposable à l'IRG</strong> (non listé Art. 68 CIDTA). Il est inclus dans la base IRG.</div>\n\n    <div class=\"sim-section\">Retenues</div>\n    <div class=\"sim-num-row\">\n      <label>Cotisation mutuelle (DA)</label>\n      <input type=\"number\" id=\"g-mutuelle\" value=\"0\" min=\"0\" step=\"100\" oninput=\"guideRecalc()\">\n    </div>\n\n    <div class=\"sim-cascade\" id=\"g-cascade\"></div>\n  </div>\n  <script>\n  (function(){\n    function fmtG(n){return Math.round(n).toLocaleString('fr-DZ')+' DA';}\n    function gv(id){return parseFloat(document.getElementById(id).value)||0;}\n\n    window.guideRecalc=function(){\n      var sb=gv('g-brut');\n      var iepPct=gv('g-iep')/100, nuisPct=gv('g-nuis')/100;\n      var respPct=gv('g-resp')/100, autresPct=gv('g-autres-pct')/100;\n      var icr=gv('g-icr'), panier=gv('g-panier'), mutuelle=gv('g-mutuelle');\n\n      document.getElementById('g-brut-lbl').textContent=fmtG(sb);\n      document.getElementById('g-panier-lbl').textContent=fmtG(panier);\n\n      var primesPct=sb*(iepPct+nuisPct+respPct+autresPct);\n      var totalGains=sb+icr+primesPct+panier;\n\n      // CNAS : panier exclu de l'assiette (Ord. n°95-01 Art. 1)\n      var baseCnas=totalGains-panier;\n      var cnasSal=baseCnas*0.09;\n\n      // IRG : panier INCLUS dans la base imposable (CIDTA Art. 68 — panier non exonéré)\n      var baseIrg=totalGains-cnasSal;\n\n      // Barème officiel DGI — Art. 104 CIDTA — Décret n°23-411 du 28/12/2023\n      // Tranches mensuelles (annuel ÷ 12) — plafond tranche 30% = 160 000 DA/mois\n      var exo=baseIrg<=30000;\n      var zoneAb2=baseIrg>30000&&baseIrg<=42500;\n      var tr=[{l:20000,t:0},{l:40000,t:.23},{l:80000,t:.27},{l:160000,t:.30},{l:320000,t:.33},{l:Infinity,t:.35}];\n      var lb=[\"N'excède pas 20 000\",\"20 001 → 40 000\",\"40 001 → 80 000\",\"80 001 → 160 000\",\"160 001 → 320 000\",\"Supérieure à 320 000\"];\n      var irgB=0,prev=0,rows='';\n      for(var i=0;i<tr.length;i++){\n        var dans=Math.min(baseIrg,tr[i].l)-prev;\n        if(dans<=0){rows+='<tr class=\"s-zero\"><td>'+lb[i]+' DA · '+(tr[i].t*100).toFixed(0)+'%</td><td>—</td></tr>';continue;}\n        var p=dans*tr[i].t;irgB+=p;\n        var isA=baseIrg>prev&&baseIrg<=tr[i].l;\n        rows+='<tr'+(isA?' class=\"s-active\"':'')+'><td>'+lb[i]+' DA · '+(tr[i].t*100).toFixed(0)+'%</td><td>+'+fmtG(p)+'</td></tr>';\n        prev=tr[i].l;if(prev>=baseIrg)break;\n      }\n      var abat40=irgB*0.40,abatNote='',abat=abat40;\n      if(abat40<1000){abat=1000;abatNote='plancher 1 000 DA';}else if(abat40>1500){abat=1500;abatNote='plafond 1 500 DA';}else{abatNote='40 % × IRG brut';}\n      var irgNet1=Math.max(0,irgB-abat);\n      var irgNet=exo?0:(zoneAb2?Math.max(0,irgNet1*(93/61)-(81213/41)):irgNet1);\n      var net=totalGains-cnasSal-irgNet-mutuelle;\n      var cnasPat=baseCnas*0.26;\n      var cout=totalGains+cnasPat;\n      var exoBadge=exo?'<span class=\"badge-exo\">✓ exonéré</span>':(zoneAb2?'<span class=\"badge-exo\" style=\"background:#fef3c7;color:#92400e\">2e abattement</span>':'');\n\n      document.getElementById('g-cascade').innerHTML=\n        '<div class=\"sim-step\"><div class=\"sim-bar sim-bar-green\"></div><div class=\"sim-sc\"><p class=\"sim-lbl\">① Total gains bruts</p><p class=\"sim-val\">'+fmtG(totalGains)+'</p>'+\n        '<p class=\"sim-detail\">Salaire de base '+fmtG(sb)+(icr>0?' + ICR/fixes '+fmtG(icr):'')+(primesPct>0?' + primes % '+fmtG(primesPct):'')+(panier>0?' + panier '+fmtG(panier)+' (non CNAS)':'')+'</p></div></div>'+\n\n        '<div class=\"sim-step\"><div class=\"sim-bar sim-bar-amber\"></div><div class=\"sim-sc\"><p class=\"sim-lbl\">② CNAS salariale 9 %</p><p class=\"sim-val sim-val-amber\">− '+fmtG(cnasSal)+'</p>'+\n        '<p class=\"sim-detail\">Base cotisable '+fmtG(baseCnas)+' × 9 % '+(panier>0?'(panier '+fmtG(panier)+' exclu)':'')+'</p></div></div>'+\n\n        '<div class=\"sim-step\"><div class=\"sim-bar sim-bar-blue\"></div><div class=\"sim-sc\"><p class=\"sim-lbl\">③ Base imposable IRG'+exoBadge+'</p><p class=\"sim-val\">'+fmtG(baseIrg)+'</p>'+\n        '<p class=\"sim-detail\">'+fmtG(totalGains)+' − '+fmtG(cnasSal)+' CNAS'+(panier>0?' — panier inclus dans la base IRG':'')+'</p>'+\n        (exo?'<div class=\"sim-exo\">Base ≤ 30 000 DA → exonération totale d'IRG (Art. 68 CIDTA).</div>':\n          '<table class=\"sim-tranches\"><tbody>'+rows+'</tbody><tfoot><tr><td>IRG brut (barème)</td><td>'+fmtG(irgB)+'</td></tr></tfoot></table>'+\n          '<div class=\"sim-abat\"><div class=\"r\"><span>Abattement 40 % × '+fmtG(irgB)+'</span><span>'+fmtG(abat40)+'</span></div>'+\n          '<div class=\"r\" style=\"color:var(--muted);font-size:10.5px\"><span>Plancher 1 000 / Plafond 1 500 DA</span><span>→ '+abatNote+'</span></div>'+\n          '<div class=\"r total\"><span>IRG après abattement</span><span>'+fmtG(irgNet1)+'</span></div></div>'+\n          (zoneAb2?'<div class=\"sim-exo\" style=\"background:#fef3c7;border-color:#f59e0b;color:#92400e\">2e abattement dégressif (30 001–42 500 DA) → IRG net = '+fmtG(irgNet)+'</div>':'')+\n          '<p class=\"sim-lbl\" style=\"margin-top:8px\">IRG net retenu</p><p class=\"sim-val sim-val-red\">− '+fmtG(irgNet)+'</p>')+\n        '</div></div>'+\n\n        (mutuelle>0?'<div class=\"sim-step\"><div class=\"sim-bar sim-bar-gray\"></div><div class=\"sim-sc\"><p class=\"sim-lbl\">Cotisation mutuelle</p><p class=\"sim-val sim-val-amber\">− '+fmtG(mutuelle)+'</p></div></div>':'')+\n\n        '<div class=\"sim-net\"><p class=\"nl\">④ Net à payer</p><p class=\"nv\">'+fmtG(net)+'</p>'+\n        '<p class=\"nd\">'+fmtG(totalGains)+' − CNAS '+fmtG(cnasSal)+' − IRG '+fmtG(irgNet)+(mutuelle>0?' − mutuelle '+fmtG(mutuelle):'')+'</p></div>'+\n\n        '<div class=\"sim-cout\"><span>Coût total employeur (salaire + CNAS pat. 26%)</span><span style=\"font-weight:700\">'+fmtG(cout)+'</span></div>'+\n        '<p style=\"font-size:10px;color:var(--muted);margin-top:6px\">CNAS patronale : CNR 17,75% + AT/MP 1,25% + CNAC 1% + retraite anticipée 0,25% + œuvres sociales 0,5% + formation 1% + FCCL 1,25% + maladie 3% = 26% — Réf. Ord. n°95-01, Loi n°83-14</p>';\n    };\n    guideRecalc();\n  })();",
  "theme2": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 2</div>\n    <div class=\"panel-title\">Administration du Personnel</div>\n    <p class=\"panel-text\">L'administration du personnel recouvre l'ensemble des actes de gestion du salarié depuis son entrée jusqu'à sa sortie : contrat, dossier, pointage, absences, congés, paie, déclarations et solde de tout compte. Elle est le socle documentaire sur lequel repose toute défense en cas de litige.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°90-11 du 21/04/1990 (Art. 12, 16, 31, 62, 64, 73, 87) · Loi n°83-14 (Obligations employeur CNAS) · Décret n°82-302 (Registre du personnel) · Décret exécutif n°90-227 (Règlement intérieur)</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>📋 Cycle de vie du salarié</h3>\n      <div class=\"steps\">\n        <div class=\"step\"><h3>1. Recrutement &amp; contrat</h3><p>Rédiger le contrat (CDI ou CDD justifié), définir salaire, poste, durée d'essai et lieu de travail. Affiliation CNAS immédiate (Art. 4, Loi 83-14).</p></div>\n        <div class=\"step\"><h3>2. Intégration</h3><p>Remettre règlement intérieur, fiche de poste, convention collective et interlocuteurs RH. Inscrire au registre du personnel.</p></div>\n        <div class=\"step\"><h3>3. Vie du contrat</h3><p>Suivre présence, absences, congés, primes, avenants, évaluations et formations.</p></div>\n        <div class=\"step\"><h3>4. Sortie &amp; STC</h3><p>Calculer solde de tout compte, émettre certificat de travail, attestation CNAS et documents CNAC si licenciement.</p></div>\n      </div>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📁 Dossier salarié minimal obligatoire</h3>\n      <ul>\n        <li>Pièce d'identité, acte de naissance, extrait de casier judiciaire.</li>\n        <li>Contrat de travail signé, avenants éventuels, fiche de poste.</li>\n        <li>Affiliation CNAS/CNR et numéro de sécurité sociale.</li>\n        <li>Relevés de congés, absences, retards et pointages.</li>\n        <li>Évaluations annuelles de performance.</li>\n        <li>Sanctions disciplinaires et courriers d'avertissement.</li>\n        <li>Attestations de formation et diplômes.</li>\n        <li>Solde de tout compte signé (archivage 10 ans).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📅 Congés payés (Loi n°90-11, Art. 31 à 36)</h3>\n      <ul>\n        <li><strong>Droit annuel minimum :</strong> 30 jours de congé par an (2,5 jours par mois de travail effectif).</li>\n        <li><strong>Majoration ancienneté :</strong> 2 jours supplémentaires par tranche de 5 ans d'ancienneté, plafonnée à 14 jours.</li>\n        <li><strong>Congé maternité :</strong> 14 semaines minimum (6 avant + 8 après accouchement). Loi n°83-11.</li>\n        <li><strong>Congé de maladie :</strong> Ouverture de droits selon Loi 83-11 (justificatif médical, indemnité journalière CNAS).</li>\n        <li><strong>Congés exceptionnels :</strong> Mariage, décès, naissance — à préciser dans la convention ou le règlement intérieur.</li>\n        <li><strong>Fractionnement :</strong> Autorisé avec accord des parties ; la première fraction ne peut être inférieure à 15 jours.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🗂️ Registres et documents obligatoires</h3>\n      <ul>\n        <li><strong>Registre du personnel :</strong> Obligatoire dès le 1er salarié (Décret n°82-302). Tenu à jour, présenté à l'inspection du travail sur demande.</li>\n        <li><strong>Règlement intérieur :</strong> Obligatoire pour tout établissement de 20 salariés et plus (Art. 87, Loi 90-11). Déposé à l'inspection, affiché dans les locaux.</li>\n        <li><strong>Registre des congés :</strong> Planification et suivi des congés annuels.</li>\n        <li><strong>Registre AT/MP :</strong> Déclaration de tout accident du travail à la CNAS sous 24h (Loi n°83-13).</li>\n        <li><strong>Journal de paie :</strong> Édition mensuelle des bulletins et récapitulatifs (conservation 10 ans).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🏁 Calcul du Solde de Tout Compte (STC)</h3>\n      <ul>\n        <li>Salaire du dernier mois (prorata jours travaillés).</li>\n        <li>Congés payés acquis non pris (2,5 j × mois travaillés).</li>\n        <li>Primes dues et non versées (13e mois pro-rata, bilan).</li>\n        <li>Indemnité de licenciement si &gt; 1 an ancienneté (Art. 73 bis, Loi 90-11).</li>\n        <li>Déductions : avances sur salaire, prêts, saisies-arrêts.</li>\n        <li><strong>Documents à délivrer :</strong> Certificat de travail, attestation CNAS (formulaire AT40), STC signé, attestation CNAC si licenciement économique.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>⏱️ Durée du travail (Loi n°90-11, Art. 24 à 30)</h3>\n      <ul>\n        <li><strong>Durée légale :</strong> 40 heures par semaine (173,33 heures par mois).</li>\n        <li><strong>HS palier 1 (≤ 8h/sem sup.) :</strong> Majoration +50 % — Art. 31, Loi 90-11.</li>\n        <li><strong>HS palier 2 (suivantes) :</strong> Majoration +75 %.</li>\n        <li><strong>HS nuit / repos légal :</strong> Majoration +100 %.</li>\n        <li><strong>Travail de nuit :</strong> Prime de nuit obligatoire, définie par la convention collective.</li>\n        <li><strong>Aménagement du temps :</strong> Accord collectif ou avenant individuel requis pour tout horaire atypique.</li>\n      </ul>\n    </div>\n  </div>",
  "theme3": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 3</div>\n    <div class=\"panel-title\">Droit du Travail</div>\n    <p class=\"panel-text\">Le droit du travail algérien est codifié principalement par la Loi n°90-11 du 21 avril 1990, modifiée et complétée. Il régit les relations individuelles et collectives de travail : contrat, rémunération, durée, congés, discipline, rupture et litiges.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°90-11 du 21/04/1990 (modifiée) · Ordonnance n°96-21 · Décret exécutif n°94-289 (IEP) · Décret n°91-316 (frais de déplacement) · Décret n°96-24 (avantages en nature) · Ord. n°06-03 (réforme du code du travail)</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>📄 Contrat de travail (Art. 11 à 22, Loi 90-11)</h3>\n      <ul>\n        <li><strong>CDI = norme légale :</strong> Présumé à durée indéterminée si rien n'est stipulé.</li>\n        <li><strong>CDD :</strong> Autorisé uniquement sur liste limitative — remplacement d'un salarié absent, surcroît temporaire d'activité, saisonnier, tâche précisément définie. Tout autre CDD est requalifiable en CDI.</li>\n        <li><strong>Période d'essai :</strong> 6 mois pour les cadres, 3 mois pour agents de maîtrise, 1 mois pour les postes d'exécution. Renouvelable une fois avec accord écrit.</li>\n        <li><strong>Mentions obligatoires :</strong> Poste, salaire, durée d'essai, lieu de travail, horaire, convention ou règlement applicable.</li>\n        <li><strong>Avenant :</strong> Toute modification substantielle nécessite un avenant écrit signé des deux parties.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>💰 Rémunération (Art. 23 à 30, Loi 90-11)</h3>\n      <ul>\n        <li><strong>Salaire minimum :</strong> Nul salaire ne peut être inférieur au SNMG (24 000 DA depuis 01/01/2024 — Décret n°23-411).</li>\n        <li><strong>IEP (Indemnité d'Expérience Professionnelle) :</strong> 1 % par année d'ancienneté dans l'entreprise, dès la 3e année, plafonné à 20 %. Décret n°94-289.</li>\n        <li><strong>Principe d'égalité :</strong> Travail égal = salaire égal. Toute discrimination salariale basée sur le sexe, l'origine ou les opinions est illicite.</li>\n        <li><strong>Mode de paiement :</strong> Mensuel, en monnaie légale, sur le territoire national. Bulletin de paie obligatoire.</li>\n        <li><strong>Retenues :</strong> Limitées aux cotisations légales, avances sur salaire (avec accord) et saisies judiciaires (plafonnées).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🚪 Rupture du contrat de travail (Art. 62 à 73, Loi 90-11)</h3>\n      <ul>\n        <li><strong>Démission :</strong> Préavis obligatoire selon ancienneté et catégorie (défini par la convention collective). Formulaire écrit.</li>\n        <li><strong>Licenciement individuel :</strong> Motif réel et sérieux. Procédure disciplinaire obligatoire. Indemnité légale si ≥ 1 an d'ancienneté.</li>\n        <li><strong>Licenciement économique :</strong> Consultation obligatoire des représentants du personnel. Information de l'inspection du travail. Plan social si ≥ 10 salariés licenciés.</li>\n        <li><strong>Retraite :</strong> 60 ans (H) / 55 ans (F) avec 15 ans de cotisation. Retraite anticipée à 50 ans avec 20 ans de cotisation (Loi 83-12).</li>\n        <li><strong>Nullité du licenciement :</strong> Licenciement abusif → réintégration ou indemnisation majorée prononcée par le tribunal.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>⚖️ Inspection du travail (Loi n°90-11, Art. 87 à 90)</h3>\n      <ul>\n        <li>Droit de visite à tout moment, sans préavis. Accès à tous les documents et registres.</li>\n        <li>Présenter contrats, registre du personnel, bulletins de salaire et déclarations sociales sur demande.</li>\n        <li>Toute infraction constatée : mise en demeure, procès-verbal, amende ou suspension d'activité.</li>\n        <li>Règlement intérieur : obligatoirement déposé à l'inspection et affiché dans les locaux avant entrée en vigueur.</li>\n        <li>Élections de délégués du personnel : obligatoires dès 9 salariés. Mandat de 3 ans (Art. 93, Loi 90-11).</li>\n        <li>Tout licenciement d'un délégué du personnel nécessite l'autorisation préalable de l'inspection du travail.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🛑 Travailleurs protégés — vigilance absolue</h3>\n      <div class=\"alert alert-red\" style=\"margin-top:0;margin-bottom:10px\">Toute sanction ou licenciement d'un travailleur protégé sans respect des procédures renforcées expose l'employeur à une annulation judiciaire et des dommages et intérêts.</div>\n      <ul>\n        <li><strong>Délégué syndical / représentant élu :</strong> Toute sanction ou mutation requiert avis de l'inspection du travail.</li>\n        <li><strong>Femme enceinte :</strong> Protection contre le licenciement pendant grossesse et congé maternité de 14 semaines (Art. 27, Loi 90-11 et Loi 83-11).</li>\n        <li><strong>Salarié en accident du travail :</strong> Interdiction de licencier pendant la période d'arrêt AT (Loi 83-13).</li>\n        <li><strong>Salarié en formation professionnelle :</strong> Protection pendant la durée du contrat de formation.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📖 Conventions collectives et règlement intérieur</h3>\n      <ul>\n        <li><strong>Convention collective :</strong> Négocie les conditions d'emploi au-delà du minimum légal. S'applique à tous les salariés de l'entreprise ou de la branche, même non syndiqués.</li>\n        <li><strong>Règlement intérieur (Art. 87, Loi 90-11) :</strong> Obligatoire ≥ 20 salariés. Fixe les règles d'hygiène, de sécurité, de discipline et les procédures de sanction. Soumis à avis des représentants du personnel avant dépôt.</li>\n        <li><strong>Hiérarchie des normes :</strong> Loi &gt; Convention collective &gt; Règlement intérieur &gt; Contrat individuel. Le contrat ne peut jamais être inférieur au plancher légal ou conventionnel.</li>\n      </ul>\n    </div>\n  </div>\n\n  <!-- ── Sous-section Télétravail & Temps de travail flexible ── -->\n  <div class=\"panel\" style=\"margin-top:16px\">\n    <div class=\"panel-kicker\">Sous-section · Priorité 3</div>\n    <div class=\"panel-title\">💻 Télétravail &amp; Temps de travail flexible</div>\n    <p class=\"panel-text\">Le télétravail n'est pas encore formellement codifié par un texte spécifique en droit algérien à la date de rédaction de ce guide. Il s'organise sur la base de la <strong>Loi n°90-11</strong> (obligations générales de l'employeur, droit au travail en conditions normales) et d'un <strong>avenant au contrat</strong> ou d'un <strong>accord d'entreprise</strong> librement négocié. L'employeur reste tenu à toutes ses obligations légales (CNAS, IRG, HSE) quel que soit le lieu de travail du salarié.</p>\n    <div class=\"panel-note\">📌 <strong>Note légale :</strong> En l'absence de loi spécifique sur le télétravail en Algérie, les éléments ci-dessous s'appuient sur les principes généraux de la Loi n°90-11, le droit comparé (France, Tunisie) et les bonnes pratiques RH. Tout accord de télétravail doit être soumis à l'inspection du travail pour validation. <strong>Restez vigilants aux évolutions législatives en cours.</strong></div>\n\n    <div class=\"grid-2\" style=\"margin-top:14px\">\n      <div class=\"rh-card\">\n        <h3>📋 Encadrement juridique actuel</h3>\n        <ul>\n          <li><strong>Base légale disponible :</strong> Loi n°90-11 Art. 6 (liberté d'organisation du travail) + Art. 11 (contenu du contrat) + Art. 87 (règlement intérieur). Le télétravail s'insère dans ces cadres généraux.</li>\n          <li><strong>Avenant contractuel obligatoire :</strong> Le passage au télétravail ou à un horaire flexible constitue une <strong>modification substantielle du contrat</strong>. Il nécessite un avenant écrit signé par les deux parties, précisant le lieu de travail alternatif, les horaires, les équipements fournis et les conditions de réversibilité.</li>\n          <li><strong>Caractère volontaire :</strong> Le télétravail ne peut être imposé unilatéralement par l'employeur (sauf circonstances exceptionnelles type pandémie). Le refus du salarié ne peut constituer un motif de licenciement.</li>\n          <li><strong>Réversibilité :</strong> L'accord doit prévoir une clause de réversibilité permettant le retour au travail présentiel à la demande de l'une ou l'autre partie, avec un délai de prévenance raisonnable.</li>\n          <li><strong>Égalité de traitement :</strong> Le télétravailleur bénéficie des mêmes droits que le salarié en présentiel : mêmes avantages, même accès à la formation, mêmes possibilités d'évolution.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🛡️ Obligations de l'employeur en télétravail</h3>\n        <ul>\n          <li><strong>Équipements :</strong> L'employeur doit fournir, installer et entretenir les équipements nécessaires au télétravail (ordinateur, accès VPN sécurisé, logiciels), sauf accord contraire précisant l'utilisation d'équipements personnels avec compensation.</li>\n          <li><strong>Sécurité informatique :</strong> L'employeur reste responsable de la sécurité des données traitées à domicile (Loi n°18-07). Politique d'accès sécurisé, chiffrement, interdiction des réseaux publics non sécurisés.</li>\n          <li><strong>Prévention des RPS :</strong> L'isolement et la porosité vie pro/perso sont des risques psychosociaux réels. L'employeur doit mettre en place des mesures préventives : réunions d'équipe régulières, points managériaux, droit à la déconnexion.</li>\n          <li><strong>Accidents du travail :</strong> Un accident survenu au domicile pendant les heures de travail déclarées est présumé accident du travail (Loi n°83-13). L'employeur doit le déclarer à la CNAS dans les délais légaux.</li>\n          <li><strong>Cotisations sociales &amp; IRG :</strong> Inchangés — le salarié en télétravail reste soumis aux mêmes règles CNAS et IRG que s'il travaillait en présentiel.</li>\n          <li><strong>Prise en charge des frais :</strong> Les frais engagés par le salarié pour l'exercice du télétravail (électricité, connexion internet, fournitures) peuvent faire l'objet d'une indemnité forfaitaire ou d'un remboursement sur justificatifs. Son régime fiscal (frais réels vs avantage) doit être clarifié.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🕐 Aménagements du temps de travail</h3>\n        <ul>\n          <li><strong>Horaires flexibles (flex-time) :</strong> Le salarié choisit ses heures d'arrivée et de départ dans une plage de flexibilité définie (ex : arrivée entre 7h et 9h30, départ entre 16h et 19h), sous réserve de respecter la durée hebdomadaire légale.</li>\n          <li><strong>Semaine de 4 jours :</strong> Non prévue par la Loi n°90-11, mais envisageable par accord d'entreprise si la durée hebdomadaire légale est respectée. Gain en bien-être perçu, mais journées plus longues à gérer (dérogation potentielle aux durées max journalières).</li>\n          <li><strong>Travail en décalé / postes rotatifs :</strong> Encadré par la Loi n°90-11 sur la durée maximale de travail. Les travailleurs de nuit et en postes rotatifs bénéficient de majorations et de protections spécifiques (pauses, surveillance médicale renforcée).</li>\n          <li><strong>Annualisation du temps de travail :</strong> Lissage sur l'année des variations d'activité (haute/basse saison), à encadrer par accord collectif. Permet d'éviter les heures supplémentaires en pointe si anticipé.</li>\n          <li><strong>Temps partiel :</strong> Autorisé par la Loi n°90-11. Le salarié à temps partiel bénéficie d'une protection proportionnelle à ses droits (congés, indemnités, IEP au prorata).</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📝 Contenu d'un avenant de télétravail</h3>\n        <ul>\n          <li><strong>Lieu(x) de télétravail :</strong> Domicile principal + éventuellement espaces de coworking agréés. Adresse précise à mentionner.</li>\n          <li><strong>Fréquence :</strong> Nombre de jours par semaine ou par mois en télétravail (ex : 2 jours/semaine). Jours fixes ou flottants.</li>\n          <li><strong>Plages horaires obligatoires :</strong> Heures de disponibilité impératives (ex : 9h-12h et 14h-17h), en dehors desquelles s'applique le droit à la déconnexion.</li>\n          <li><strong>Équipements :</strong> Liste des équipements fournis par l'employeur, modalités de restitution, responsabilité en cas de perte ou détérioration.</li>\n          <li><strong>Frais :</strong> Montant de l'indemnité télétravail si prévue, mode de calcul et de versement.</li>\n          <li><strong>Sécurité des données :</strong> Engagements du salarié (réseau sécurisé, VPN, confidentialité).</li>\n          <li><strong>Réversibilité :</strong> Délai de prévenance pour retour en présentiel (ex : 1 mois), sans motif à justifier.</li>\n          <li><strong>Durée :</strong> Durée de l'avenant (période d'essai recommandée de 3-6 mois avant pérennisation).</li>\n        </ul>\n      </div>\n    </div>\n\n    <!-- Tableau synthèse -->\n    <div style=\"overflow-x:auto;margin-top:16px\">\n      <table class=\"rate-tbl\" style=\"width:100%;border-collapse:collapse\">\n        <thead>\n          <tr style=\"background:var(--navy,#1e3a5f);color:#fff\">\n            <th style=\"text-align:left;padding:10px 12px\">Aspect</th>\n            <th style=\"text-align:left;padding:10px 12px\">Présentiel classique</th>\n            <th style=\"text-align:left;padding:10px 12px\">Télétravail</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr><td style=\"padding:9px 12px\">Lieu de travail</td><td style=\"padding:9px 12px\">Locaux de l'entreprise</td><td style=\"padding:9px 12px\">Domicile / coworking (défini dans l'avenant)</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Contrat</td><td style=\"padding:9px 12px\">Contrat original</td><td style=\"padding:9px 12px\">Avenant obligatoire (modification substantielle)</td></tr>\n          <tr><td style=\"padding:9px 12px\">CNAS / IRG</td><td style=\"padding:9px 12px\">Taux légaux normaux</td><td style=\"padding:9px 12px\">Identiques — aucun changement</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Accidents du travail</td><td style=\"padding:9px 12px\">Couvert Loi n°83-13</td><td style=\"padding:9px 12px\">Couvert si pendant heures déclarées — déclarer à CNAS</td></tr>\n          <tr><td style=\"padding:9px 12px\">Équipements</td><td style=\"padding:9px 12px\">Fournis par employeur</td><td style=\"padding:9px 12px\">Fournis par employeur ou indemnité si personnels</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Congés &amp; droits</td><td style=\"padding:9px 12px\">Loi n°90-11</td><td style=\"padding:9px 12px\">Identiques — pas de régime dérogatoire</td></tr>\n          <tr><td style=\"padding:9px 12px\">Réversibilité</td><td style=\"padding:9px 12px\">Non applicable</td><td style=\"padding:9px 12px\">Délai de prévenance prévu dans l'avenant</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Base légale spécifique</td><td style=\"padding:9px 12px\">Loi n°90-11</td><td style=\"padding:9px 12px\">Loi n°90-11 (générale) + avenant + accord d'entreprise</td></tr>\n        </tbody>\n      </table>\n    </div>\n  </div>",
  "theme4": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 4</div>\n    <div class=\"panel-title\">Droit Syndical et Instances Représentatives</div>\n    <p class=\"panel-text\">La Loi n°23-02 rénove le cadre du droit syndical en Algérie en consacrant le pluralisme syndical, en définissant des critères de représentativité et en renforçant la protection des représentants du personnel. Tout employeur doit maîtriser ces règles pour sécuriser sa gestion sociale.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°23-02 (droit syndical, 2023) · Loi n°90-11 Art. 91 à 97 (délégués du personnel) · Loi n°90-02 (règlement des conflits collectifs) · Décret exécutif n°96-318 (conciliation et médiation)</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>🏛️ Loi n°23-02 — Droit syndical (2023)</h3>\n      <ul>\n        <li><strong>Pluralisme syndical :</strong> Reconnaît la coexistence de plusieurs syndicats dans un même secteur ou entreprise.</li>\n        <li><strong>Représentativité :</strong> Un syndicat est représentatif s'il obtient au moins 20 % des suffrages exprimés lors des élections professionnelles.</li>\n        <li><strong>Droits des syndicats représentatifs :</strong> Négocier les conventions collectives, siéger dans les organismes paritaires, disposer de locaux syndicaux dans l'entreprise.</li>\n        <li><strong>Liberté d'adhésion :</strong> Aucun salarié ne peut être contraint d'adhérer ou de ne pas adhérer à un syndicat.</li>\n        <li>Remplace la loi n°90-14 du 2 juin 1990 relative aux modalités d'exercice du droit syndical.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>👥 Délégués du personnel (Loi 90-11, Art. 91 à 97)</h3>\n      <ul>\n        <li><strong>Seuil d'élection :</strong> Obligatoire dans tout établissement d'au moins 9 salariés.</li>\n        <li><strong>Mandat :</strong> 3 ans, renouvelable. Élection à bulletin secret par l'ensemble des salariés.</li>\n        <li><strong>Missions :</strong> Présenter les réclamations individuelles et collectives, veiller à l'application des lois et conventions, participer aux négociations salariales.</li>\n        <li><strong>Crédits d'heures :</strong> Heures de délégation payées comme temps de travail (nombre fixé par convention ou règlement intérieur).</li>\n        <li><strong>Accès :</strong> Droit de circuler librement dans l'entreprise et d'afficher les communications syndicales sur panneaux dédiés.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🛡️ Protection des représentants du personnel</h3>\n      <ul>\n        <li>Aucune sanction, mutation ou licenciement ne peut être prononcé à l'encontre d'un délégué ou représentant syndical sans l'autorisation préalable de l'inspection du travail.</li>\n        <li>Cette protection s'étend pendant la durée du mandat et pendant 6 mois après son expiration.</li>\n        <li>En cas de licenciement abusif : réintégration obligatoire prononcée par le tribunal ou indemnité majorée.</li>\n        <li>Toute entrave à l'exercice du mandat est passible de sanctions pénales (Art. 37, Loi 23-02).</li>\n        <li>Documenter systématiquement tout motif professionnel objectif pour toute décision affectant un représentant.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>⚡ Conflits collectifs et droit de grève</h3>\n      <ul>\n        <li><strong>Procédure de conciliation :</strong> Obligatoire avant tout dépôt de préavis de grève. Délégation portant les revendications formulées par écrit.</li>\n        <li><strong>Préavis de grève :</strong> 10 jours minimum avant le déclenchement. Notification à l'employeur et à l'inspection du travail.</li>\n        <li><strong>Service minimum :</strong> Obligatoire dans les secteurs essentiels (santé, eau, énergie, transports, sécurité). Défini par accord ou par décret. Loi n°90-02.</li>\n        <li><strong>Lock-out :</strong> Fermeture temporaire autorisée uniquement en réponse à une grève illicite ou à un danger grave pour les biens et personnes.</li>\n        <li><strong>Médiation :</strong> Si la conciliation échoue, recours à un médiateur désigné par accord mutuel ou l'inspection du travail (Décret n°96-318).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🤝 Négociation collective — bonnes pratiques RH</h3>\n      <ul>\n        <li>Organiser des réunions régulières avec les délégués du personnel (au moins une fois par mois).</li>\n        <li>Rédiger des procès-verbaux de réunion signés par toutes les parties.</li>\n        <li>Informer et consulter avant tout changement organisationnel majeur (restructuration, plan de charge, modification des horaires).</li>\n        <li>Traiter les réclamations individuelles dans un délai raisonnable et documenté.</li>\n        <li>Fournir les informations économiques et sociales demandées par les représentants dans le cadre de leurs missions légales.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📋 Réflexes RH — conformité syndicale</h3>\n      <div class=\"alert alert-amber\" style=\"margin-top:0;margin-bottom:10px\">La méconnaissance des droits syndicaux est une source majeure de conflits et de contentieux. Anticiper vaut mieux que subir.</div>\n      <ul>\n        <li>Organiser les élections de délégués dans les délais légaux et afficher les résultats.</li>\n        <li>Mettre à disposition les locaux syndicaux et les panneaux d'affichage dédiés.</li>\n        <li>Ne jamais interférer dans la vie interne d'un syndicat (financement, orientation, activité).</li>\n        <li>Consulter un conseil juridique avant toute décision pouvant affecter un représentant du personnel.</li>\n        <li>Conserver tous les procès-verbaux de réunions sociales (au moins 5 ans).</li>\n      </ul>\n    </div>\n  </div>",
  "theme5": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 5</div>\n    <div class=\"panel-title\">Santé et Sécurité au Travail</div>\n    <p class=\"panel-text\">La SST est une obligation légale impérative. L'employeur est responsable de la santé physique et mentale de ses salariés et doit prévenir les risques professionnels, déclarer les accidents et organiser la médecine du travail. Tout manquement engage sa responsabilité civile, voire pénale.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°88-07 du 26/01/1988 (hygiène, sécurité et médecine du travail) · Loi n°83-13 (AT/MP, réparations) · Décret exécutif n°91-05 (prescriptions générales de protection) · Décret exécutif n°05-09 (comités HSE) · Ord. n°95-07 (assurances)</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>⚠️ Obligations générales de l'employeur (Loi n°88-07)</h3>\n      <ul>\n        <li>Évaluer et prévenir tous les risques professionnels (physiques, chimiques, biologiques, psychosociaux).</li>\n        <li>Fournir gratuitement les Équipements de Protection Individuelle (EPI) adaptés aux risques.</li>\n        <li>Organiser la formation à la sécurité de tout salarié lors de l'embauche, de changement de poste ou d'introduction de nouveaux équipements.</li>\n        <li>Afficher les consignes de sécurité, les plans d'évacuation et les numéros d'urgence dans chaque atelier ou bureau.</li>\n        <li>Maintenir les locaux, équipements et installations en état de conformité et de propreté.</li>\n        <li>Tenir à jour le Document Unique d'Évaluation des Risques (DUER) — mis à jour annuellement.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🏥 Médecine du travail (Loi n°88-07, Art. 29 à 41)</h3>\n      <ul>\n        <li><strong>Visites médicales obligatoires :</strong> Embauche, annuelle pour tous les salariés, semestrielle pour les postes à risques (bruit, produits chimiques, écrans).</li>\n        <li><strong>Aptitude au poste :</strong> Le médecin du travail délivre une fiche d'aptitude. Un salarié déclaré inapte ne peut être maintenu au poste concerné.</li>\n        <li><strong>Rôle du médecin du travail :</strong> Conseil en prévention, formation aux premiers secours, étude des postes de travail, propositions d'aménagement.</li>\n        <li><strong>Confidentialité :</strong> Les données médicales ne sont jamais communiquées à l'employeur (secret médical).</li>\n        <li>En l'absence de service médical interne : adhésion obligatoire à un service de médecine du travail interentreprises agréé.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🚨 Accident du travail — procédure légale (Loi n°83-13)</h3>\n      <ul>\n        <li><strong>Définition :</strong> Tout accident survenu par le fait ou à l'occasion du travail, quelle qu'en soit la cause (Art. 6, Loi 83-13).</li>\n        <li><strong>Déclaration :</strong> L'employeur déclare l'AT à la CNAS dans les <strong>24 heures</strong> (formulaire AT1). Toute déclaration tardive est passible d'amende.</li>\n        <li><strong>Registre AT :</strong> Tout AT, même bénin (sans arrêt), doit être enregistré dans le registre d'AT de l'établissement.</li>\n        <li><strong>Prestations CNAS :</strong> Prise en charge à 100 % des soins. Indemnité journalière AT (100 % du salaire net). Rente d'incapacité si séquelles.</li>\n        <li><strong>Maladie professionnelle :</strong> Reconnue par le médecin-conseil CNAS sur la base du tableau officiel des MP. Mêmes droits que l'AT.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🏗️ Comité Hygiène, Sécurité et Environnement (CHSE)</h3>\n      <ul>\n        <li><strong>Obligation :</strong> Obligatoire dans tout établissement de 20 salariés et plus (Décret exécutif n°05-09 du 08/01/2005).</li>\n        <li><strong>Composition :</strong> Présidé par le directeur ou son représentant. Comprend le médecin du travail et des représentants des salariés.</li>\n        <li><strong>Missions :</strong> Analyse des accidents, inspection des lieux de travail, propositions de mesures préventives, élaboration du plan de prévention annuel.</li>\n        <li><strong>Réunions :</strong> Au moins une fois par trimestre et après tout accident grave ou presqu'accident.</li>\n        <li>Procès-verbaux des réunions CHSE conservés 5 ans et présentables à l'inspection du travail.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📊 Indicateurs SST à suivre</h3>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Taux de fréquence AT = (Nb AT avec arrêt × 10⁶) / Heures travaillées</div>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Taux de gravité AT = (Nb jours perdus × 10³) / Heures travaillées</div>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Taux d'absentéisme maladie = (H absence maladie / H théoriques) × 100</div>\n      <ul style=\"margin-top:10px\">\n        <li>Déclarations AT mensuelles à la CNAS (formulaire mensuel de sinistralité).</li>\n        <li>Rapport annuel CHSE présenté à la direction et aux représentants du personnel.</li>\n        <li>Plan de prévention annuel avec budget dédié et suivi d'exécution.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🧯 Réflexes SST — conformité employeur</h3>\n      <div class=\"alert alert-red\" style=\"margin-top:0;margin-bottom:10px\">Un accident du travail non déclaré ou une infraction SST constatée par l'inspection expose l'employeur à des amendes, des poursuites pénales et la responsabilité civile.</div>\n      <ul>\n        <li>Actualiser le DUER chaque année et après tout événement grave.</li>\n        <li>Tenir à jour le registre des AT et le rapport médical annuel.</li>\n        <li>Organiser des exercices d'évacuation au moins une fois par an.</li>\n        <li>S'assurer que les installations électriques, de levage et sous pression font l'objet de contrôles périodiques par des organismes agréés.</li>\n        <li>Nommer un animateur sécurité dans chaque unité de production.</li>\n      </ul>\n    </div>\n  </div>",
  "theme6": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 6</div>\n    <div class=\"panel-title\">Gestion des Conflits et Procédures Disciplinaires</div>\n    <p class=\"panel-text\">La procédure disciplinaire en Algérie est strictement encadrée par la Loi n°90-11. Elle impose une graduation des sanctions, le respect du droit de défense et la proportionnalité de la peine. Toute violation de la procédure expose l'employeur à une annulation judiciaire de la sanction.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°90-11 Art. 63 à 78 (discipline, rupture) · Loi n°90-02 du 06/02/1990 (prévention et règlement des conflits collectifs) · Décret exécutif n°96-318 (conciliation et médiation) · Code de procédure civile et administrative (recours juridictionnel)</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>⚖️ Les 4 degrés de sanctions disciplinaires (Loi 90-11, Art. 73)</h3>\n      <div class=\"alert alert-blue\" style=\"margin-top:0;margin-bottom:10px\">La sanction doit être proportionnelle à la faute. Toute sanction supérieure au 1er degré nécessite une procédure contradictoire.</div>\n      <ul>\n        <li><strong>1er degré — Avertissement écrit / blâme :</strong> Faute légère, premier manquement. Aucun effet sur la rémunération. Conservation dans le dossier.</li>\n        <li><strong>2e degré — Mise à pied :</strong> Suspension temporaire avec retenue de salaire proportionnelle. Durée limitée (définie par règlement intérieur ou convention).</li>\n        <li><strong>3e degré — Rétrogradation :</strong> Changement de classification, de fonction ou de poste avec impact sur la rémunération. Avenant de modification de contrat requis.</li>\n        <li><strong>4e degré — Licenciement pour faute :</strong> Faute grave ou lourde. Procédure renforcée obligatoire. Motif réel, sérieux et documenté.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📋 Procédure disciplinaire — étapes obligatoires</h3>\n      <ul>\n        <li><strong>1. Qualifier les faits :</strong> Date, heure, lieu, nature de la faute, témoins éventuels. Rapport écrit du responsable hiérarchique.</li>\n        <li><strong>2. Convocation écrite :</strong> Lettre recommandée avec AR ou remise en main propre contre décharge. Préciser l'objet de l'entretien et le droit de se faire assister.</li>\n        <li><strong>3. Entretien préalable :</strong> Le salarié présente ses explications. Un représentant du personnel peut l'assister. Procès-verbal signé.</li>\n        <li><strong>4. Décision motivée :</strong> Notification écrite de la sanction choisie, proportionnée à la faute.</li>\n        <li><strong>5. Notification :</strong> Lettre recommandée avec AR ou remise contre décharge. Délai légal à respecter.</li>\n        <li><strong>Prescription :</strong> Aucune faute ne peut être sanctionnée plus de 2 mois après que l'employeur en a eu connaissance (sauf procédure pénale en cours).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🤝 Gestion des conflits individuels</h3>\n      <ul>\n        <li><strong>Conciliation interne :</strong> Première étape. Entretien avec le responsable RH et le manager. Objectif : trouver une solution amiable documentée.</li>\n        <li><strong>Médiation :</strong> Si l'échec de la conciliation interne, recours à un médiateur (extérieur à l'entreprise ou désigné par accord des parties).</li>\n        <li><strong>Inspection du travail :</strong> Le salarié peut saisir l'inspection pour toute violation de ses droits. L'inspecteur peut intervenir en conciliation.</li>\n        <li><strong>Juridiction du travail :</strong> Tribunal territorialement compétent. Délai de prescription de l'action individuelle : 2 ans à compter du fait générateur.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🔥 Gestion des conflits collectifs (Loi n°90-02)</h3>\n      <ul>\n        <li><strong>Signaux d'alerte :</strong> Hausse de l'absentéisme, ralentissement de la production, pétitions, tensions lors des réunions, réclamations répétitives.</li>\n        <li><strong>Conciliation :</strong> Obligatoire avant tout préavis de grève. Délégation salariale déposant les revendications par écrit à la direction.</li>\n        <li><strong>Préavis de grève :</strong> 10 jours minimum. Notification simultanée à l'employeur et à l'inspection du travail.</li>\n        <li><strong>Arbitrage :</strong> En cas d'échec de la conciliation, recours à un arbitre agréé. La sentence arbitrale s'impose aux deux parties.</li>\n        <li>Maintenir un canal de dialogue permanent pour anticiper et désamorcer les tensions avant l'escalade.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📌 Fautes graves justifiant le licenciement immédiat</h3>\n      <ul>\n        <li>Vol, détournement ou escroquerie au préjudice de l'employeur.</li>\n        <li>Ivresse manifeste ou consommation de stupéfiants sur le lieu de travail.</li>\n        <li>Violence physique ou verbale grave envers un supérieur, un collègue ou un client.</li>\n        <li>Divulgation de secrets professionnels ou de fabrication.</li>\n        <li>Abandon de poste non justifié de façon répétée (après mise en demeure).</li>\n        <li>Refus caractérisé et délibéré d'exécuter les instructions de travail légitimes.</li>\n        <li>Falsification de documents officiels ou de relevés de pointage.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📄 Documents à conserver (preuve)</h3>\n      <ul>\n        <li>Rapport de constat des faits signé par le(s) responsable(s) hiérarchique(s).</li>\n        <li>Convocation à l'entretien préalable (accusé de réception).</li>\n        <li>Procès-verbal d'entretien disciplinaire signé par les parties.</li>\n        <li>Lettre de notification de la sanction (accusé de réception).</li>\n        <li>Tout élément de preuve : relevé de pointage, rapport de sécurité, témoignages écrits.</li>\n        <li>Conservation minimum : <strong>5 ans après la sortie</strong> du salarié.</li>\n      </ul>\n    </div>\n  </div>",
  "theme7": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 7</div>\n    <div class=\"panel-title\">Formation Professionnelle et Taxe de Formation</div>\n    <p class=\"panel-text\">La formation professionnelle est à la fois une obligation légale et un levier stratégique. L'employeur est tenu de financer le développement des compétences via la Taxe d'Apprentissage et de Formation (TAF) et la Taxe sur la Formation Professionnelle Continue (TFPC). Un plan de formation bien construit améliore la performance et sécurise la GPEC.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°81-07 du 27/06/1981 (formation professionnelle continue) · Loi de Finances (TAF et TFPC — chaque année) · Décret exécutif n°05-490 (modalités de la formation continue) · Décret n°94-289 (IEP et lien avec la formation) · Loi n°90-11 Art. 56 (obligation de formation)</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>💰 Taxe de Formation — obligations fiscales</h3>\n      <ul>\n        <li><strong>Taxe d'Apprentissage et de Formation (TAF) :</strong> Incluse dans la Taxe sur l'Activité Professionnelle (TAP). Taux et modalités fixés par la Loi de Finances annuelle.</li>\n        <li><strong>Taxe sur la Formation Professionnelle Continue (TFPC) :</strong> Due par les entreprises de 20 salariés et plus. Calculée sur la masse salariale brute annuelle. Versée à la FNAC (Fonds National de l'Assurance Chômage) ou utilisée directement en actions de formation.</li>\n        <li><strong>Imputation :</strong> Les dépenses réelles de formation peuvent être imputées sur la taxe due à condition de conserver les justificatifs (conventions, factures, attestations de présence).</li>\n        <li><strong>Déclaration :</strong> Formulaire de déclaration annuelle des actions de formation à déposer à la direction de la formation professionnelle.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📅 Plan de formation annuel — construction</h3>\n      <ul>\n        <li><strong>1. Recueil des besoins :</strong> Entretiens annuels, évaluations de performance, demandes des managers et des salariés.</li>\n        <li><strong>2. Priorisation :</strong> Aligner les besoins individuels sur les objectifs stratégiques de l'entreprise et les exigences réglementaires (sécurité, hygiène, qualité).</li>\n        <li><strong>3. Construction du plan :</strong> Identifier les actions (interne/externe), les formateurs, le calendrier, le budget et les indicateurs de succès.</li>\n        <li><strong>4. Validation :</strong> Soumettre le plan aux représentants du personnel pour consultation.</li>\n        <li><strong>5. Exécution et suivi :</strong> Feuilles de présence, évaluations à chaud et à froid, attestations de formation.</li>\n        <li><strong>6. Rapport :</strong> Bilan annuel de formation intégré au tableau de bord RH.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🎓 Types d'actions de formation</h3>\n      <ul>\n        <li><strong>Formation initiale :</strong> Qualification lors de l'embauche (adaptation au poste).</li>\n        <li><strong>Formation continue :</strong> Maintien et perfectionnement des compétences en cours d'emploi.</li>\n        <li><strong>Formation réglementaire :</strong> Sécurité (habilitations électriques, CACES, SST), hygiène alimentaire, etc. Obligatoire pour certains postes.</li>\n        <li><strong>Formation à la reconversion :</strong> Préparer un salarié à un nouveau poste ou métier (lié à la GPEC).</li>\n        <li><strong>Formation en apprentissage :</strong> Contrat d'apprentissage pour les jeunes. Avantages fiscaux et exonérations de charges.</li>\n        <li><strong>E-learning / présentiel :</strong> Les deux modes sont reconnus si sanctionnés par une attestation.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📊 Indicateurs formation à suivre</h3>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Taux d'effort formation = (Budget formation / Masse salariale) × 100</div>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Taux d'accès à la formation = (Nb salariés formés / Effectif total) × 100</div>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Coût moyen par salarié formé = Budget formation / Nb salariés formés</div>\n      <ul style=\"margin-top:10px\">\n        <li>Nombre moyen d'heures de formation par salarié et par an.</li>\n        <li>Taux de réalisation du plan (actions effectuées / planifiées).</li>\n        <li>ROI formation : impact sur la performance, réduction des erreurs, progression salariale.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🔑 Droits du salarié en formation (Loi 81-07, Art. 56 Loi 90-11)</h3>\n      <ul>\n        <li>Le salarié ne peut se voir refuser une formation prévue au plan de formation sans motif légitime.</li>\n        <li>La formation pendant le temps de travail est assimilée à du temps de travail effectif, rémunéré normalement.</li>\n        <li>Les frais pédagogiques, de déplacement et d'hébergement sont à la charge de l'employeur pour les formations imposées.</li>\n        <li>Toute formation qualifiante ouvre droit à une attestation certifiée remise au salarié.</li>\n        <li>Une clause de dédit-formation peut être prévue pour les formations coûteuses (durée d'engagement à préciser dans l'avenant).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🏛️ Dispositifs publics et FNAC</h3>\n      <ul>\n        <li><strong>FNAC (Fonds National de l'Assurance Chômage) :</strong> Cofinance des actions de formation et de reconversion pour les salariés menacés de licenciement économique.</li>\n        <li><strong>INEFP (Institut National de l'Emploi et de la Formation Professionnelle) :</strong> Organisme public de référence pour les formations certifiantes.</li>\n        <li><strong>ANADE / ANGEM :</strong> Dispositifs emploi-jeunes avec exonérations de charges et prise en charge de la formation à l'entrepreneuriat.</li>\n        <li>Les frais de formation financés via ces dispositifs sont déductibles de la TFPC due.</li>\n      </ul>\n    </div>\n  </div>",
  "theme8": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 8</div>\n    <div class=\"panel-title\">GPEC et Recrutement</div>\n    <p class=\"panel-text\">La Gestion Prévisionnelle des Emplois et des Compétences (GPEC) permet d'anticiper les évolutions des métiers et d'adapter les effectifs et les compétences aux besoins futurs. Le recrutement en est le levier d'alimentation : il doit être structuré, équitable et conforme au droit du travail algérien.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°90-11 Art. 11 à 22 (contrat de travail, embauche) · Décret exécutif n°06-154 (emploi de travailleurs étrangers) · Décret n°94-289 (IEP) · Loi n°04-19 du 25/12/2004 (placement des travailleurs)</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>🔮 GPEC — Gestion Prévisionnelle des Emplois et Compétences</h3>\n      <ul>\n        <li><strong>Cartographie des emplois :</strong> Lister tous les postes, leurs missions, les compétences requises et les effectifs actuels. Base de toute démarche GPEC.</li>\n        <li><strong>Analyse des écarts :</strong> Comparer les compétences disponibles aux compétences cibles à horizon 3-5 ans.</li>\n        <li><strong>Plan d'action :</strong> Recrutement, formation, mobilité interne, promotion, reconversion, ou réduction d'effectifs.</li>\n        <li><strong>Gestion des emplois sensibles :</strong> Identifier les postes à risque d'obsolescence ou de pénurie et anticiper.</li>\n        <li><strong>Plans de succession :</strong> Préparer les relèves pour les postes clés (cadres dirigeants, experts rares).</li>\n        <li>Mettre à jour la cartographie annuellement et lors de tout changement organisationnel majeur.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🔍 Processus de recrutement — étapes clés</h3>\n      <ul>\n        <li><strong>1. Expression du besoin :</strong> Fiche de poste précise (missions, compétences, expérience, conditions, salaire).</li>\n        <li><strong>2. Sourcing :</strong> Interne (mobilité, promotion) puis externe (ANEM, cabinets, jobboards, réseaux).</li>\n        <li><strong>3. Présélection :</strong> Tri des CV sur critères objectifs définis en amont. Grille de sélection documentée.</li>\n        <li><strong>4. Entretiens :</strong> Structurés avec grille d'évaluation. Associer le manager opérationnel.</li>\n        <li><strong>5. Tests et vérifications :</strong> Tests techniques, psychométriques, vérification des références et diplômes.</li>\n        <li><strong>6. Décision et offre :</strong> Offre d'emploi écrite précisant poste, salaire, durée d'essai et date de prise de poste.</li>\n        <li><strong>7. Onboarding :</strong> Intégration structurée, désignation d'un tuteur, bilan de fin de période d'essai.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📄 Règles légales du recrutement (Loi 90-11)</h3>\n      <ul>\n        <li><strong>Non-discrimination :</strong> Aucun critère de sexe, d'âge, d'origine, de religion ou d'opinion ne peut fonder un refus d'embauche (Art. 6 et 17, Loi 90-11).</li>\n        <li><strong>Travailleurs étrangers :</strong> Soumis à autorisation préalable du MTESS (Décret n°06-154). Quota maximum selon le secteur.</li>\n        <li><strong>Affiliation CNAS :</strong> Obligatoire dès le premier jour de travail, même pendant la période d'essai (Art. 4, Loi 83-14).</li>\n        <li><strong>CDD :</strong> Uniquement sur motifs légaux limitativement énumérés (Art. 12, Loi 90-11). Tout CDD illicite est requalifié en CDI par le juge.</li>\n        <li><strong>Stage et apprentissage :</strong> Régis par des contrats spécifiques. Interdiction formelle de substituer un stagiaire à un poste permanent.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📊 Indicateurs recrutement et GPEC</h3>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Délai moyen de recrutement = (Date embauche − Date ouverture poste) en jours</div>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Coût moyen recrutement = (Frais sourcing + temps RH + onboarding) / Nb recrutements</div>\n      <div class=\"kpi-formula\" style=\"margin:6px 0\">Taux de rétention à 1 an = (Salariés encore en poste à 12 mois / Nb embauchés) × 100</div>\n      <ul style=\"margin-top:10px\">\n        <li>Taux de réussite de période d'essai.</li>\n        <li>Ratio promotions internes / recrutements externes.</li>\n        <li>Indice de couverture des postes critiques (succession planning).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🏛️ ANEM — Agence Nationale de l'Emploi</h3>\n      <ul>\n        <li>Intermédiation gratuite entre employeurs et demandeurs d'emploi (Loi n°04-19).</li>\n        <li>L'employeur peut déposer une offre d'emploi sur le portail ANEM (obligation légale avant tout recrutement externe pour certains secteurs).</li>\n        <li>Services : présélection de candidats, organisation d'entretiens collectifs, aide aux recrutements de masse.</li>\n        <li>Dispositifs d'aide à l'emploi : DAIP (Dispositif d'Aide à l'Insertion Professionnelle) — exonérations de charges pour les primo-employeurs.</li>\n        <li>Obligation de déclarer toute embauche à l'ANEM dans les 30 jours suivant la prise de poste.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🗺️ Grille de classification et rémunération (GPEC)</h3>\n      <ul>\n        <li>Chaque poste doit être classifié selon la grille de classification de la convention collective applicable ou du règlement intérieur.</li>\n        <li>La grille de classification fonde la politique salariale équitable et transparente.</li>\n        <li>Réviser la grille en parallèle de toute revalorisation du SNMG pour s'assurer qu'aucun poste ne soit sous le seuil légal.</li>\n        <li>Documenter les critères de promotion (ancienneté, performance, certification) pour éviter les contestations.</li>\n        <li>L'IEP (1 % par an d'ancienneté, plafonné à 20 %) doit être intégré dans la simulation de la masse salariale prévisionnelle (Décret n°94-289).</li>\n      </ul>\n    </div>\n  </div>\n\n  <!-- ── ENRICHISSEMENT : Marque employeur & Expérience collaborateur ── -->\n  <div class=\"panel\" style=\"margin-top:4px\">\n    <div class=\"panel-kicker\">Marque employeur</div>\n    <div class=\"panel-title\">🏆 Marque employeur &amp; Attractivité des talents</div>\n    <p class=\"panel-text\">La marque employeur désigne la réputation d'une organisation en tant qu'employeur, perçue à la fois par ses salariés actuels et par les candidats potentiels. En Algérie, le marché des talents qualifiés est de plus en plus concurrentiel. Une marque employeur forte réduit le coût et le délai de recrutement, améliore la rétention et renforce la mobilisation des équipes.</p>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>📡 Leviers de la marque employeur</h3>\n        <ul>\n          <li><strong>Proposition de valeur employeur (EVP) :</strong> Ce qui différencie l'entreprise en tant qu'employeur — rémunération, culture, développement, équilibre vie pro/perso, sécurité de l'emploi. Doit être authentique et cohérente avec la réalité vécue.</li>\n          <li><strong>Présence digitale :</strong> Page carrières sur le site web, profil LinkedIn entreprise, présence sur les job boards algériens (Emploi.dz, Rekrute). Témoignages de salariés (vidéos, articles).</li>\n          <li><strong>Relations écoles &amp; universités :</strong> Partenariats avec les grandes écoles et universités algériennes, stages, forums emploi, bourses. Vivier de futurs talents fidélisés avant même l'embauche.</li>\n          <li><strong>Cooptation structurée :</strong> Programme de recommandation interne avec reconnaissance (prime ou reconnaissance symbolique). Réduit le coût recrutement et améliore la qualité des embauches.</li>\n          <li><strong>Communication interne cohérente :</strong> Les salariés sont les premiers ambassadeurs. Ce qu'ils disent à l'extérieur définit la marque réelle.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📊 Indicateurs de marque employeur</h3>\n        <div class=\"kpi-formula\" style=\"margin:8px 0\">Taux d'acceptation d'offre = (Offres acceptées / Offres émises) × 100</div>\n        <div class=\"kpi-formula\" style=\"margin:8px 0\">NPS interne = % Promoteurs − % Détracteurs (salariés)</div>\n        <div class=\"kpi-formula\" style=\"margin:8px 0\">Ancienneté moyenne = Σ anciennetés / Effectif total</div>\n        <div class=\"kpi-formula\" style=\"margin:8px 0\">Taux de rétention à 1 an = (Présents à 12 mois / Embauchés) × 100</div>\n        <div class=\"kpi-formula\" style=\"margin:8px 0\">Taux de promotion interne = (Promus internes / Total recrutements) × 100</div>\n        <ul style=\"margin-top:10px\">\n          <li>Suivi mensuel du taux d'acceptation d'offre — en dessous de 70 %, revoir l'EVP ou les conditions proposées.</li>\n          <li>NPS interne mesuré 2 fois par an via enquête anonyme (3 questions simples).</li>\n          <li>Comparer l'ancienneté moyenne à la moyenne du secteur — un écart négatif signale un problème de fidélisation.</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Onboarding structuré -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Intégration</div>\n    <div class=\"panel-title\">🚀 Onboarding structuré — De J1 à M6</div>\n    <p class=\"panel-text\">Un onboarding réussi multiplie par 2 la rétention à 1 an et réduit le délai de montée en compétences. Il ne se limite pas à l'accueil administratif du premier jour — il s'étale sur 6 mois et implique RH, manager et équipe.</p>\n    <div style=\"overflow-x:auto;margin-top:12px\">\n      <table class=\"rate-tbl\" style=\"width:100%;border-collapse:collapse\">\n        <thead>\n          <tr style=\"background:var(--navy,#1e3a5f);color:#fff\">\n            <th style=\"text-align:left;padding:10px 12px;width:130px\">Étape</th>\n            <th style=\"text-align:left;padding:10px 12px\">Actions RH &amp; Manager</th>\n            <th style=\"text-align:left;padding:10px 12px\">Livrables / Jalons</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr style=\"background:var(--surface2,#f8fafc)\">\n            <td style=\"padding:10px 12px;font-weight:700;color:var(--teal,#0d9488)\">Avant J1<br><small style=\"font-weight:400;color:var(--muted,#6b7280)\">(pré-boarding)</small></td>\n            <td style=\"padding:10px 12px\">Envoi du contrat signé et du règlement intérieur · Confirmation de la date de prise de poste · Préparation du poste de travail, badge, matériel informatique, accès · Information de l'équipe d'accueil · Désignation du tuteur/parrain</td>\n            <td style=\"padding:10px 12px\">☐ Contrat signé reçu<br>☐ Poste &amp; matériel prêts<br>☐ Tuteur désigné<br>☐ CNAS affilié (à partir du 1er jour)</td>\n          </tr>\n          <tr>\n            <td style=\"padding:10px 12px;font-weight:700;color:var(--teal,#0d9488)\">Jour 1</td>\n            <td style=\"padding:10px 12px\">Accueil personnalisé par le DRH + manager · Remise des documents (RI, fiche de poste, organigramme, livret d'accueil) · Tour de l'entreprise et présentation des équipes · Déjeuner avec l'équipe · Configuration des accès informatiques</td>\n            <td style=\"padding:10px 12px\">☐ Documents remis &amp; signés<br>☐ Accès SIRH activés<br>☐ Équipe présentée<br>☐ Premier échange avec le manager</td>\n          </tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\">\n            <td style=\"padding:10px 12px;font-weight:700;color:var(--teal,#0d9488)\">Semaine 1</td>\n            <td style=\"padding:10px 12px\">Formation aux outils métier · Présentation des process et procédures clés · Réunion de cadrage avec le manager (objectifs de la période d'essai) · Point quotidien informel tuteur/recrue · Visite médicale d'embauche (médecine du travail)</td>\n            <td style=\"padding:10px 12px\">☐ Objectifs période d'essai formalisés<br>☐ Visite médicale planifiée<br>☐ Formations outils planifiées</td>\n          </tr>\n          <tr>\n            <td style=\"padding:10px 12px;font-weight:700;color:var(--teal,#0d9488)\">Mois 1</td>\n            <td style=\"padding:10px 12px\">Bilan intermédiaire RH + manager (ressenti, difficultés, besoins) · Ajustement du plan de formation si nécessaire · Présentation aux clients/partenaires clés · Point sur les objectifs de la période d'essai</td>\n            <td style=\"padding:10px 12px\">☐ Bilan M1 documenté<br>☐ Plan formation ajusté<br>☐ Feedback salarié recueilli</td>\n          </tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\">\n            <td style=\"padding:10px 12px;font-weight:700;color:var(--teal,#0d9488)\">Mois 3</td>\n            <td style=\"padding:10px 12px\">Entretien de mi-période d'essai (évaluation formelle) · Confirmation ou non de la poursuite · Ajustement des objectifs · Enquête de satisfaction d'intégration anonyme · Identification des besoins de développement</td>\n            <td style=\"padding:10px 12px\">☐ Évaluation mi-essai formalisée<br>☐ Décision de confirmation documentée<br>☐ Enquête intégration réalisée</td>\n          </tr>\n          <tr>\n            <td style=\"padding:10px 12px;font-weight:700;color:var(--teal,#0d9488)\">Mois 6</td>\n            <td style=\"padding:10px 12px\">Bilan de fin d'intégration (RH + manager + salarié) · Validation de la titularisation ou du renouvellement · Définition du plan de développement individuel · Intégration dans les cycles normaux de management (entretien annuel prochain)</td>\n            <td style=\"padding:10px 12px\">☐ Bilan M6 signé<br>☐ Plan développement défini<br>☐ Intégré dans l'entretien annuel</td>\n          </tr>\n        </tbody>\n      </table>\n    </div>\n  </div>\n\n  <!-- Exit interview & enquêtes -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Fidélisation</div>\n    <div class=\"panel-title\">🎤 Exit Interview &amp; Enquêtes d'engagement</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>🚪 Exit Interview — Entretien de départ</h3>\n        <ul>\n          <li><strong>Objectif :</strong> Comprendre les véritables raisons du départ (push factors : management, salaire, ambiance, perspectives) et identifier les axes d'amélioration internes.</li>\n          <li><strong>Timing :</strong> Mener l'entretien dans les derniers jours de présence, par un RH neutre (pas le manager direct). Peut être complété par un questionnaire anonyme post-départ.</li>\n          <li><strong>Questions clés :</strong> Qu'est-ce qui vous a conduit à chercher ailleurs ? Qu'aurait-on pu faire pour vous retenir ? Que recommanderiez-vous d'améliorer ? Recommanderiez-vous l'entreprise à un ami ?</li>\n          <li><strong>Traitement :</strong> Compiler les résultats trimestriellement. Si 3 départs ou plus mentionnent le même motif, c'est un signal d'action, pas une coïncidence.</li>\n          <li><strong>Confidentialité :</strong> Les réponses ne doivent pas être transmises au manager concerné directement — synthèse anonymisée à la direction.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📋 Enquêtes d'engagement (Pulse surveys)</h3>\n        <ul>\n          <li><strong>Principe :</strong> Questionnaire court (5-10 questions) envoyé régulièrement (trimestriel ou semestriel) pour mesurer le moral, l'engagement et la satisfaction des équipes.</li>\n          <li><strong>Thèmes à couvrir :</strong> Clarté des objectifs, qualité du management, reconnaissance, développement professionnel, conditions de travail, fierté d'appartenance.</li>\n          <li><strong>NPS interne :</strong> « Recommanderiez-vous cette entreprise comme employeur à quelqu'un de votre entourage ? » (note de 0 à 10). NPS = % 9-10 (promoteurs) − % 0-6 (détracteurs).</li>\n          <li><strong>Règle d'or :</strong> Ne pas lancer une enquête sans communiquer les résultats et sans plan d'action. Une enquête sans suite détériore la confiance.</li>\n          <li><strong>Anonymat garanti :</strong> Condition sine qua non de la sincérité des réponses. Utiliser un outil tiers ou un formulaire anonymisé.</li>\n        </ul>\n      </div>\n    </div>\n  </div>",
  "theme9": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 9</div>\n    <div class=\"panel-title\">Pilotage RH et Reporting</div>\n    <p class=\"panel-text\">Une DRH efficace passe de l'administration réactive au management proactif grâce aux données. Le pilotage RH repose sur un tableau de bord d'indicateurs clés (KPI) permettant de décider, d'alerter et de convaincre la direction avec des chiffres fiables et actualisés.</p>\n    <div class=\"panel-note\">📌 <strong>Références :</strong> Aucune obligation légale spécifique de reporting RH interne en dehors des déclarations obligatoires (DAS, DAC, CNAS). Le pilotage relève des bonnes pratiques managériales et des exigences de gouvernance de l'entreprise.</div>\n  </div>\n\n  <div class=\"kpi-grid\">\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">💰</div>\n      <h4>Masse salariale</h4>\n      <p>Total des rémunérations brutes versées (salaires, primes, HS, congés). Suivre mensuel, trimestriel et annuel.</p>\n      <div class=\"kpi-formula\">MS = Σ (bruts) + charges patronales (25 %)</div>\n    </div>\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">💼</div>\n      <h4>Coût employeur / salarié</h4>\n      <p>Coût réel incluant toutes les charges patronales (CNAS 25 %) et frais annexes.</p>\n      <div class=\"kpi-formula\">= Brut × 1,25 + frais divers</div>\n    </div>\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">📉</div>\n      <h4>Taux d'absentéisme</h4>\n      <p>Part des heures perdues vs heures théoriques. Cible recommandée : &lt; 3 % dans l'industrie.</p>\n      <div class=\"kpi-formula\">= (H absences / H théoriques) × 100</div>\n    </div>\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">🔄</div>\n      <h4>Taux de turnover</h4>\n      <p>Mesure la rotation du personnel. Au-delà de 15 % : signal de dysfonctionnement managérial ou salarial.</p>\n      <div class=\"kpi-formula\">= (Départs / Effectif moyen) × 100</div>\n    </div>\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">🏋️</div>\n      <h4>Effort de formation</h4>\n      <p>Part du budget formation dans la masse salariale. Indicateur GPEC et fiscal (TFPC).</p>\n      <div class=\"kpi-formula\">= (Budget formation / MS) × 100</div>\n    </div>\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">⚠️</div>\n      <h4>Taux de fréquence AT</h4>\n      <p>Accidents du travail pour 1 million d'heures travaillées. Obligation légale de suivi (Loi 83-13).</p>\n      <div class=\"kpi-formula\">= (Nb AT × 10⁶) / H travaillées</div>\n    </div>\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">⏱️</div>\n      <h4>Heures supplémentaires</h4>\n      <p>Suivi du volume et du coût des HS. Signe de surcharge ou de sous-effectif chronique.</p>\n      <div class=\"kpi-formula\">= Σ (HS × taux majoré) / MS × 100</div>\n    </div>\n    <div class=\"kpi\">\n      <div class=\"kpi-icon\">🎯</div>\n      <h4>Délai moyen de recrutement</h4>\n      <p>Mesure l'efficacité du processus RH. Un délai long coûte en productivité.</p>\n      <div class=\"kpi-formula\">= (Date embauche − Date ouverture) jours</div>\n    </div>\n  </div>\n\n  <div class=\"grid-2\" style=\"margin-top:14px\">\n    <div class=\"rh-card\">\n      <h3>📊 Tableau de bord RH mensuel — données clés</h3>\n      <ul>\n        <li>Masse salariale totale et coût employeur du mois.</li>\n        <li>Évolution des effectifs : entrées, sorties, solde net.</li>\n        <li>Taux d'absentéisme global et par service (maladie, AT, injustifié).</li>\n        <li>Volume et coût des heures supplémentaires.</li>\n        <li>Accidents du travail déclarés et taux de fréquence cumulé.</li>\n        <li>Avancement du plan de formation (budget consommé / prévu).</li>\n        <li>Postes vacants et durée moyenne de recrutement.</li>\n        <li>Nombre de sanctions disciplinaires et de conflits en cours.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📈 Reporting périodique — cadence recommandée</h3>\n      <ul>\n        <li><strong>Mensuel :</strong> Tableau de bord RH complet (MS, effectifs, absentéisme, AT, HS, recrutements). Destinataires : DG, DAF, responsables de service.</li>\n        <li><strong>Trimestriel :</strong> Analyse des tendances, comparaison N-1, alertes sur indicateurs hors norme.</li>\n        <li><strong>Semestriel :</strong> Point formation (plan vs réalisé), GPEC, revue des postes critiques.</li>\n        <li><strong>Annuel :</strong> Bilan social, rapport CHSE, DAS/DAC, plan de formation N+1, revue salariale et ajustements.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🗃️ Déclarations obligatoires — calendrier fiscal et social</h3>\n      <table class=\"tbl-lite\">\n        <thead><tr><th>Déclaration</th><th>Échéance</th><th>Destinataire</th></tr></thead>\n        <tbody>\n          <tr><td>CNAS mensuelle</td><td>Avant le 15 du mois suivant</td><td>CNAS</td></tr>\n          <tr><td>IRG retenu à la source</td><td>Mensuel — calendrier DGI</td><td>DGI</td></tr>\n          <tr><td>DAC annuelle</td><td>31 janvier (N+1)</td><td>CNAS</td></tr>\n          <tr><td>DAS annuelle</td><td>30 avril (N+1)</td><td>DGI</td></tr>\n          <tr><td>Déclaration AT</td><td>24 heures après l'accident</td><td>CNAS</td></tr>\n          <tr><td>Rapport annuel CHSE</td><td>Janvier (N+1)</td><td>Inspection du travail</td></tr>\n          <tr><td>Bilan formation (TFPC)</td><td>Variable — DFP</td><td>Direction formation professionnelle</td></tr>\n        </tbody>\n      </table>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🖥️ Système d'Information RH (SIRH)</h3>\n      <ul>\n        <li>Centraliser toutes les données salariés, paie, congés, formation, AT dans un outil unique.</li>\n        <li>Automatiser les calculs de paie, les alertes sur les échéances légales et la génération des déclarations.</li>\n        <li>Sécuriser les données personnelles : accès restreint, sauvegardes régulières, conformité au respect de la vie privée.</li>\n        <li>Produire les KPI automatiquement pour alimenter le tableau de bord mensuel.</li>\n        <li>Assurer la traçabilité des modifications (qui a changé quoi et quand) pour l'audit social.</li>\n      </ul>\n    </div>\n  </div>",
  "theme10": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 10</div>\n    <div class=\"panel-title\">Stratégie et Climat Social</div>\n    <p class=\"panel-text\">La stratégie RH doit s'aligner sur la stratégie globale de l'entreprise. Le climat social est le baromètre de la santé organisationnelle : un bon climat favorise la performance, réduit l'absentéisme et le turnover, et prévient les conflits. Il se construit sur la durée par des politiques cohérentes, transparentes et équitables.</p>\n    <div class=\"panel-note\">📌 <strong>Références :</strong> Loi n°90-11 (relations collectives) · Loi n°23-02 (dialogue social) · Loi n°90-02 (prévention des conflits) · Circulaires MTESS sur le dialogue social en entreprise.</div>\n  </div>\n\n  <div class=\"grid-2\">\n    <div class=\"rh-card\">\n      <h3>🎯 Aligner la stratégie RH sur la stratégie d'entreprise</h3>\n      <ul>\n        <li><strong>Diagnostic stratégique RH :</strong> Analyse SWOT des ressources humaines (forces, faiblesses, opportunités, menaces sur les effectifs et compétences).</li>\n        <li><strong>Objectifs RH stratégiques :</strong> Fixer des cibles à 3 ans : effectifs cibles, masse salariale maîtrisée, taux de formation, objectifs de turnover et d'absentéisme.</li>\n        <li><strong>Politique salariale :</strong> Définir une politique de rémunération compétitive, équitable et soutenable financièrement, intégrant les évolutions du SNMG et de l'IEP.</li>\n        <li><strong>Marque employeur :</strong> Travailler l'attractivité de l'entreprise pour recruter et retenir les talents dans un marché de l'emploi compétitif.</li>\n        <li><strong>RSE et impact social :</strong> Intégrer les dimensions de responsabilité sociale (emploi local, formation, inclusion, sécurité) dans la stratégie RH.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🌡️ Mesurer et améliorer le climat social</h3>\n      <ul>\n        <li><strong>Enquête de satisfaction salariés :</strong> Questionnaire annuel anonyme sur les conditions de travail, le management, la rémunération, la formation et la communication interne.</li>\n        <li><strong>Indicateurs de climat :</strong> Absentéisme, turnover, nombre de réclamations, conflits individuels, participation aux réunions sociales.</li>\n        <li><strong>Baromètre social :</strong> Suivi trimestriel de la satisfaction et de l'engagement. Alertes sur les services ou équipes à risque.</li>\n        <li><strong>Plan d'action :</strong> Chaque enquête débouche sur un plan d'action concret, communiqué et suivi avec les représentants du personnel.</li>\n        <li>Un climat social dégradé non traité se traduit par une hausse des conflits, de l'absentéisme et une chute de la productivité.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🤝 Dialogue social et prévention des conflits</h3>\n      <ul>\n        <li>Instaurer des réunions régulières avec les délégués du personnel (au moins mensuelles).</li>\n        <li>Partager des informations économiques et sociales transparentes avec les représentants.</li>\n        <li>Mettre en place un dispositif de remontée des réclamations anonymes (boîte à suggestions, ligne RH directe).</li>\n        <li>Former les managers à la communication et à la gestion des tensions d'équipe.</li>\n        <li>Intervenir tôt sur les signaux faibles : absentéisme localisé, micro-conflits répétitifs, démotivation visible.</li>\n        <li>Valoriser les accords conclus par la négociation plutôt que les décisions unilatérales.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>🚀 Politiques RH structurantes</h3>\n      <ul>\n        <li><strong>Politique de rémunération :</strong> Grille de salaires transparente, révisions salariales annuelles, politique de primes liée à la performance et aux résultats.</li>\n        <li><strong>Politique de formation :</strong> Investissement visible, plan pluriannuel, lien direct entre formation et évolution de carrière.</li>\n        <li><strong>Politique de mobilité interne :</strong> Favoriser la promotion interne avant tout recrutement externe. Communiquer toutes les opportunités en interne.</li>\n        <li><strong>Politique QVT (Qualité de Vie au Travail) :</strong> Aménagement des espaces, flexibilité, prévention des RPS (Risques Psychosociaux), soutien aux salariés en difficulté.</li>\n        <li><strong>Politique de reconnaissance :</strong> Valoriser formellement les contributions individuelles et collectives (entretien annuel, prime, remerciement public).</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>⚡ Risques Psychosociaux (RPS) — prévention</h3>\n      <ul>\n        <li><strong>Définition :</strong> Stress chronique, harcèlement moral ou sexuel, épuisement professionnel (burnout), violences internes ou externes au travail.</li>\n        <li><strong>Obligation employeur :</strong> Prévenir les RPS dans le cadre de l'évaluation des risques professionnels (DUER — Loi 88-07).</li>\n        <li><strong>Signaux d'alerte :</strong> Hausse du turnover, arrêts maladies répétitifs, conflits interpersonnels, plaintes de harcèlement, baisse de productivité localisée.</li>\n        <li><strong>Actions :</strong> Formation des managers, dispositif d'écoute confidentielle, médiation, accompagnement psychologique et révision de l'organisation du travail.</li>\n        <li>Tout cas de harcèlement moral ou sexuel avéré doit faire l'objet d'une procédure disciplinaire à l'encontre de l'auteur.</li>\n      </ul>\n    </div>\n    <div class=\"rh-card\">\n      <h3>📋 Plan stratégique RH — structure type</h3>\n      <ul>\n        <li><strong>Volet 1 — Effectifs :</strong> Cibles d'effectifs à 3 ans, plans de recrutement et de départs maîtrisés.</li>\n        <li><strong>Volet 2 — Compétences :</strong> GPEC, plan de formation pluriannuel, plans de succession pour postes critiques.</li>\n        <li><strong>Volet 3 — Rémunération :</strong> Révision de la grille salariale, politique de primes, maîtrise de la masse salariale.</li>\n        <li><strong>Volet 4 — Relations sociales :</strong> Protocole de dialogue, agenda social annuel, politique de prévention des conflits.</li>\n        <li><strong>Volet 5 — SST et bien-être :</strong> Plan de prévention AT, politique QVT, programme de prévention des RPS.</li>\n        <li><strong>Volet 6 — Performance RH :</strong> Tableau de bord, reporting, revue annuelle et ajustements.</li>\n      </ul>\n    </div>\n  </div>",
  "theme11": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 11</div>\n    <div class=\"panel-title\">Retraite &amp; Prévoyance Sociale</div>\n    <p class=\"panel-text\">La retraite en Algérie est gérée par la <strong>Caisse Nationale des Retraites (CNR)</strong>, instituée par la Loi n°83-12 du 02/07/1983. Tout salarié du secteur formel cotise obligatoirement au régime CNR tout au long de sa carrière. Le DRH joue un rôle clé lors du départ en retraite : calcul des droits, préparation du dossier, liquidation du solde de tout compte et démarches auprès des organismes sociaux.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°83-12 du 02/07/1983 relative à la retraite (modifiée) · Loi n°97-13 du 31/05/1997 (retraite anticipée) · Art. 68 CIDTA (exonération IRG pensions) · Décret exécutif n°06-373 (taux cotisation CNR) · Loi n°83-11 (assurances sociales) · Ord. n°95-07 (mutuelle complémentaire)</div>\n  </div>\n\n  <!-- Conditions de départ -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Conditions légales</div>\n    <div class=\"panel-title\">Départ en retraite normale et anticipée</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>🎯 Retraite normale</h3>\n        <ul>\n          <li><strong>Âge :</strong> 60 ans pour les hommes, 55 ans pour les femmes.</li>\n          <li><strong>Durée de cotisation :</strong> 15 ans minimum d'activité cotisée (180 trimestres ou 60 trimestres selon les textes modificatifs — vérifier la version applicable).</li>\n          <li><strong>Déclenchement :</strong> Sur demande volontaire du salarié ou sur décision de l'employeur lorsque l'âge légal et la durée minimale sont réunis.</li>\n          <li><strong>Droits acquis :</strong> La pension est calculée sur la base du salaire moyen des meilleures années de cotisation.</li>\n          <li><strong>Continuité de couverture :</strong> Le retraité conserve la couverture maladie CNAS (assurances sociales) à titre de retraité.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>⏩ Retraite anticipée</h3>\n        <ul>\n          <li><strong>Base légale :</strong> Loi n°97-13 du 31/05/1997 relative à la retraite anticipée.</li>\n          <li><strong>Conditions :</strong> 50 ans minimum + 20 ans de cotisation effective, ou travailleurs exerçant des métiers pénibles ou exposés aux risques (liste fixée par décret).</li>\n          <li><strong>Cotisation spécifique :</strong> 0,25 % salarié + 0,25 % patron prélevée sur l'assiette CNAS pour financer ce dispositif (Décret n°06-373).</li>\n          <li><strong>Pénalité de départ anticipé :</strong> La pension peut être réduite selon un coefficient actuariel si la durée de cotisation n'est pas complète.</li>\n          <li><strong>Secteurs spécifiques :</strong> Mines, chimie, hydraulique, travaux souterrains — conditions allégées fixées par décret sectoriel.</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Calcul de la pension -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Calcul CNR</div>\n    <div class=\"panel-title\">Méthode de calcul de la pension de retraite</div>\n    <p class=\"panel-text\">La pension CNR est calculée à partir du <strong>salaire de référence</strong> (moyenne des meilleures rémunérations déclarées) et d'un <strong>taux de liquidation</strong> évoluant selon la durée de cotisation.</p>\n    <div class=\"formula-grid\">\n      <div class=\"formula\"><strong>① Salaire de référence (SR)</strong><span>Moyenne des salaires annuels bruts déclarés à la CNR sur les meilleures années (généralement les 10 dernières). Les primes non mensuelles et les avantages en nature sont pris en compte s'ils ont donné lieu à cotisation.</span></div>\n      <div class=\"formula\"><strong>② Taux de liquidation (TL)</strong><span>2,5 % par année de cotisation effective, plafonné à 80 % du salaire de référence. Exemple : 30 ans de cotisation → TL = 75 % ; 32 ans → TL = 80 % (plafond atteint).</span></div>\n      <div class=\"formula\"><strong>③ Pension mensuelle brute</strong><span>Pension = SR × TL ÷ 12. Le montant minimum de pension ne peut être inférieur au SNMG en vigueur (24 000 DA/mois depuis 01/01/2024).</span></div>\n      <div class=\"formula\"><strong>④ Régime fiscal de la pension</strong><span>Exonérée d'IRG si ≤ 20 000 DA/mois (Art. 68 CIDTA). Au-delà de ce seuil, la partie excédentaire est soumise au barème IRG progressif après abattement de 40 % (min 1 000 / max 1 500 DA). Non cotisable CNAS salariale.</span></div>\n    </div>\n    <div class=\"panel\" style=\"margin-top:14px;border-left:3px solid var(--amber,#d97706);background:var(--surface2,#fffbeb)\">\n      <div class=\"panel-kicker\">Tableau des seuils CNR / IRG</div>\n      <div style=\"overflow-x:auto\">\n        <table class=\"rate-tbl\" style=\"width:100%;border-collapse:collapse\">\n          <thead><tr style=\"background:var(--surface3,#f1f5f9)\"><th style=\"text-align:left;padding:8px\">Indicateur</th><th style=\"text-align:left;padding:8px\">Montant</th><th style=\"text-align:left;padding:8px\">Référence</th></tr></thead>\n          <tbody>\n            <tr><td style=\"padding:8px\">Pension minimum garantie</td><td style=\"padding:8px\"><strong>24 000 DA/mois</strong> (= SNMG)</td><td style=\"padding:8px\">Décret n°23-411 + Loi n°83-12</td></tr>\n            <tr><td style=\"padding:8px\">Seuil exonération IRG pension</td><td style=\"padding:8px\"><strong>≤ 20 000 DA/mois</strong> → IRG = 0</td><td style=\"padding:8px\">Art. 68 CIDTA</td></tr>\n            <tr><td style=\"padding:8px\">Taux liquidation maximum</td><td style=\"padding:8px\"><strong>80 %</strong> du salaire de référence</td><td style=\"padding:8px\">Loi n°83-12 modifiée</td></tr>\n            <tr><td style=\"padding:8px\">Cotisation CNR salarié</td><td style=\"padding:8px\"><strong>6,75 %</strong> de l'assiette CNAS</td><td style=\"padding:8px\">Décret exécutif n°06-373</td></tr>\n            <tr><td style=\"padding:8px\">Cotisation CNR patronale</td><td style=\"padding:8px\"><strong>7,50 %</strong> de l'assiette CNAS</td><td style=\"padding:8px\">Décret exécutif n°06-373</td></tr>\n            <tr><td style=\"padding:8px\">Cotisation retraite anticipée sal.</td><td style=\"padding:8px\"><strong>0,25 %</strong> de l'assiette CNAS</td><td style=\"padding:8px\">Décret exécutif n°06-373</td></tr>\n            <tr><td style=\"padding:8px\">Cotisation retraite anticipée pat.</td><td style=\"padding:8px\"><strong>0,25 %</strong> de l'assiette CNAS</td><td style=\"padding:8px\">Décret exécutif n°06-373</td></tr>\n            <tr><td style=\"padding:8px\">Âge légal — hommes</td><td style=\"padding:8px\"><strong>60 ans</strong></td><td style=\"padding:8px\">Loi n°83-12</td></tr>\n            <tr><td style=\"padding:8px\">Âge légal — femmes</td><td style=\"padding:8px\"><strong>55 ans</strong></td><td style=\"padding:8px\">Loi n°83-12</td></tr>\n            <tr><td style=\"padding:8px\">Âge retraite anticipée</td><td style=\"padding:8px\"><strong>50 ans minimum</strong></td><td style=\"padding:8px\">Loi n°97-13</td></tr>\n          </tbody>\n        </table>\n      </div>\n      <div class=\"panel-note\" style=\"margin-top:10px\">⚠️ <strong>Note :</strong> Les modalités exactes de calcul du salaire de référence (nombre d'années retenues, indexation) peuvent avoir été modifiées par des textes d'application ultérieurs. Consultez la CNR ou le MTESS pour confirmation sur le régime en vigueur à la date de départ.</div>\n    </div>\n  </div>\n\n  <!-- Prévoyance sociale -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Prévoyance</div>\n    <div class=\"panel-title\">Capital décès, rente de réversion &amp; mutuelle complémentaire</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>🪦 Capital décès (CNAS)</h3>\n        <ul>\n          <li><strong>Bénéficiaires :</strong> Ayants droit (conjoint, enfants à charge) du salarié décédé en activité ou du retraité décédé.</li>\n          <li><strong>Montant :</strong> Forfait fixé réglementairement, équivalant à plusieurs mois de salaire minimum. Se renseigner auprès de la CNAS pour le montant actualisé.</li>\n          <li><strong>Démarche :</strong> Déclaration du décès à la CNAS par l'employeur (salarié en activité) ou par la famille (retraité). Fournir acte de décès, livret de famille, RIB des ayants droit.</li>\n          <li><strong>Base légale :</strong> Loi n°83-11 du 02/07/1983 relative aux assurances sociales.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>👨‍👩‍👧 Rente de réversion (CNR)</h3>\n        <ul>\n          <li><strong>Définition :</strong> Pension versée au conjoint survivant (et aux orphelins) d'un retraité décédé ou d'un assuré décédé ayant validé la durée de cotisation minimale.</li>\n          <li><strong>Taux :</strong> En général 75 % de la pension principale du défunt pour le conjoint (vérifier le taux exact auprès de la CNR).</li>\n          <li><strong>Conditions :</strong> Mariage antérieur au décès, non remariage du conjoint survivant (selon les textes d'application).</li>\n          <li><strong>Base légale :</strong> Loi n°83-12 — dispositions relatives aux pensions de réversion.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🏥 Mutuelle complémentaire</h3>\n        <ul>\n          <li><strong>Rôle :</strong> Complète les remboursements de la CNAS pour les frais médicaux, chirurgie, lunettes, prothèses, hospitalisations. Les retraités peuvent y adhérer à titre volontaire.</li>\n          <li><strong>Cadre légal :</strong> Ord. n°95-07 du 25/01/1995 relative aux assurances (régit les mutuelles de prévoyance complémentaire).</li>\n          <li><strong>Participation employeur :</strong> Certaines conventions collectives ou accords d'entreprise prévoient une prise en charge partielle des cotisations mutuelle par l'employeur (non obligatoire en droit commun algérien).</li>\n          <li><strong>Déduction fiscale :</strong> Les cotisations mutuelle versées par l'employeur pour le compte du salarié peuvent être exonérées d'IRG dans certaines limites — vérifier avec la DGI.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>💼 Indemnité de départ en retraite (IDR)</h3>\n        <ul>\n          <li><strong>Nature :</strong> Gratification versée par l'employeur lors du départ en retraite, distincte de la pension CNR. Son montant est fixé par la convention collective, le règlement intérieur ou la négociation individuelle.</li>\n          <li><strong>Régime social :</strong> Non soumise aux cotisations CNAS (rupture du contrat).</li>\n          <li><strong>Régime fiscal :</strong> Exonérée d'IRG dans la limite des montants légaux ou conventionnels. Au-delà, la fraction excédentaire est imposable au taux libératoire de 10 %.</li>\n          <li><strong>Base légale :</strong> Loi n°83-12 · Convention collective applicable · Art. 73 et s. Loi n°90-11.</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Démarches administratives -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Procédure RH</div>\n    <div class=\"panel-title\">Démarches administratives de départ en retraite</div>\n    <p class=\"panel-text\">Le départ en retraite nécessite une coordination rigoureuse entre l'employeur, le salarié et la CNR. Le DRH est le pivot de cette procédure. Anticipez au moins <strong>3 à 6 mois avant la date de départ prévue</strong>.</p>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>📋 Étapes côté employeur</h3>\n        <ol style=\"padding-left:18px;line-height:2\">\n          <li>Vérification des conditions légales (âge, durée de cotisation).</li>\n          <li>Information écrite du salarié avec préavis légal ou conventionnel.</li>\n          <li>Établissement de l'<strong>attestation de travail</strong> et du <strong>certificat de travail</strong>.</li>\n          <li>Établissement du <strong>relevé de carrière</strong> (récapitulatif des salaires cotisés).</li>\n          <li>Calcul et paiement du <strong>solde de tout compte</strong> (STC) : salaire dernier mois, congés non pris, IDR, préavis si applicable.</li>\n          <li>Remise du <strong>reçu pour solde de tout compte</strong> signé par le salarié.</li>\n          <li>Déclaration de sortie auprès de la <strong>CNAS</strong> (formulaire de radiation).</li>\n          <li>Remise de l'<strong>attestation d'affiliation CNAS</strong> et du <strong>relevé de cotisations</strong>.</li>\n        </ol>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📋 Étapes côté salarié (dossier CNR)</h3>\n        <ol style=\"padding-left:18px;line-height:2\">\n          <li>Demande de retraite à déposer auprès de l'agence CNR compétente.</li>\n          <li><strong>Carte nationale d'identité</strong> (originale + copie).</li>\n          <li><strong>Livret de famille</strong> (originale + copie).</li>\n          <li><strong>Carnet CNAS / attestation d'affiliation</strong>.</li>\n          <li><strong>Relevé de carrière</strong> délivré par l'employeur ou reconstitué auprès de la CNAS.</li>\n          <li><strong>Attestation de travail</strong> de tous les employeurs successifs.</li>\n          <li><strong>Certificat de travail</strong> du dernier employeur.</li>\n          <li><strong>RIB bancaire</strong> pour le versement de la pension.</li>\n          <li>Photos d'identité récentes (nombre selon l'agence CNR).</li>\n          <li>Formulaire de demande de retraite CNR dûment rempli.</li>\n        </ol>\n      </div>\n    </div>\n\n    <!-- Checklist téléchargeable -->\n    <div style=\"margin-top:16px;background:var(--surface2,#f8fafc);border:1px solid var(--border,#e2e8f0);border-radius:10px;padding:16px\">\n      <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;gap:12px;flex-wrap:wrap\">\n        <strong style=\"font-size:14px\">✅ Checklist documents départ en retraite</strong>\n        <button onclick=\"copyChecklist()\" style=\"background:var(--teal,#0d9488);color:#fff;border:none;border-radius:6px;padding:6px 14px;font-size:12px;cursor:pointer;font-weight:600\">📋 Copier la checklist</button>\n      </div>\n      <div id=\"checklist-retraite\" style=\"font-size:13px;line-height:2;color:var(--ink-soft,#374151)\">\n        <div>☐ &nbsp;Demande de retraite (formulaire CNR)</div>\n        <div>☐ &nbsp;Copie CNI recto-verso</div>\n        <div>☐ &nbsp;Copie livret de famille</div>\n        <div>☐ &nbsp;Attestation d'affiliation CNAS</div>\n        <div>☐ &nbsp;Relevé de carrière complet (tous employeurs)</div>\n        <div>☐ &nbsp;Attestation(s) de travail — tous employeurs</div>\n        <div>☐ &nbsp;Certificat de travail — dernier employeur</div>\n        <div>☐ &nbsp;Solde de tout compte signé</div>\n        <div>☐ &nbsp;Reçu pour solde de tout compte</div>\n        <div>☐ &nbsp;RIB bancaire (compte au nom du retraité)</div>\n        <div>☐ &nbsp;Photos d'identité récentes (× 4 minimum)</div>\n        <div>☐ &nbsp;Déclaration de sortie CNAS (formulaire employeur)</div>\n        <div>☐ &nbsp;Relevé de cotisations CNR</div>\n        <div>☐ &nbsp;Attestation de non-assurance maladie complémentaire (si applicable)</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- FAQ retraite -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Questions fréquentes</div>\n    <div class=\"panel-title\">FAQ — Retraite en Algérie</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>❓ Un employeur peut-il forcer le départ en retraite ?</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Oui, lorsque le salarié a atteint l'âge légal (60/55 ans) ET la durée minimale de cotisation. L'employeur doit respecter le préavis légal ou conventionnel et informer la CNAS. La mise en retraite d'office sans les conditions réunies peut constituer un licenciement abusif.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>❓ La pension est-elle imposable à l'IRG ?</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Non si elle est ≤ 20 000 DA/mois (Art. 68 CIDTA). Au-delà, la partie excédentaire est imposable selon le barème IRG progressif après l'abattement habituel de 40 %. C'est la CNR ou la banque qui effectue la retenue à la source sur les montants supérieurs au seuil.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>❓ Le salarié peut-il cumuler pension et activité ?</h3>\n        <p style=\"font-size:13px;line-height:1.7\">En principe, le cumul emploi-retraite est encadré en Algérie. Le retraité qui reprend une activité salariée peut voir sa pension suspendue ou réduite. Il convient de consulter la CNR pour les règles précises applicables à chaque situation individuelle.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>❓ Que se passe-t-il si la pension n'est pas encore liquidée ?</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Pendant la période de traitement du dossier CNR, le salarié n'est plus rémunéré par l'employeur après la date effective de départ. L'employeur doit s'assurer que le dossier est déposé à temps pour éviter toute rupture de revenus. Une avance sur droits CNR peut être demandée à l'agence locale.</p>\n      </div>\n    </div>\n  </div>",
  "theme12": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 12 — Priorité 2</div>\n    <div class=\"panel-title\">🔒 Protection des données RH — Loi n°18-07</div>\n    <p class=\"panel-text\">La <strong>Loi n°18-07 du 10 juin 2018</strong> relative à la protection des personnes physiques dans le traitement des données à caractère personnel constitue le cadre juridique fondamental de la protection de la vie privée en Algérie. Pour le DRH, elle impose des obligations précises sur la collecte, le traitement, la conservation et la sécurité des données des salariés. Son non-respect expose l'entreprise à des sanctions pénales et administratives.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Loi n°18-07 du 10/06/2018 · Loi n°06-01 du 20/02/2006 (corruption, dispose de règles sur les données) · Code pénal algérien (Art. 303 bis et s.) · Règlement intérieur de l'entreprise · Loi n°90-11 Art. 7 (droit à la vie privée du salarié)</div>\n  </div>\n\n  <!-- Principes fondamentaux -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Principes clés</div>\n    <div class=\"panel-title\">Les 6 principes fondamentaux de la Loi 18-07</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>1️⃣ Licéité &amp; finalité</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Tout traitement de données RH doit avoir une <strong>finalité légitime, explicite et déterminée</strong>. Les données collectées à l'embauche ne peuvent pas être utilisées à d'autres fins sans consentement explicite. Exemples de finalités légitimes : exécution du contrat de travail, paie, formation, évaluation des performances.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>2️⃣ Minimisation des données</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Seules les données <strong>strictement nécessaires</strong> à la finalité déclarée doivent être collectées. Il est interdit de collecter des données sur l'état de santé détaillé, les opinions politiques ou religieuses, la vie sexuelle, sauf exception légale stricte (médecine du travail pour les données de santé).</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>3️⃣ Consentement éclairé</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Le salarié doit être <strong>informé</strong> des traitements dont il fait l'objet : nature des données, finalité, destinataires, droits dont il dispose. Cette information peut figurer dans le contrat de travail, le règlement intérieur ou une notice de confidentialité remise à l'embauche.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>4️⃣ Exactitude</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Les données doivent être <strong>exactes, complètes et mises à jour</strong>. Le responsable du traitement (l'employeur) est tenu de corriger ou supprimer les données inexactes. Le salarié peut demander la rectification de ses données personnelles à tout moment.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>5️⃣ Sécurité &amp; confidentialité</h3>\n        <p style=\"font-size:13px;line-height:1.7\">L'employeur doit mettre en œuvre des <strong>mesures techniques et organisationnelles</strong> adaptées pour protéger les données contre toute perte, destruction, divulgation non autorisée ou accès illicite (contrôle d'accès SIRH, chiffrement, sauvegarde, gestion des habilitations).</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>6️⃣ Durée de conservation limitée</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Les données ne peuvent être conservées <strong>au-delà de la durée nécessaire</strong> à la finalité du traitement. À l'issue de cette durée, elles doivent être supprimées, anonymisées ou archivées selon un régime d'archivage légal distinct.</p>\n      </div>\n    </div>\n  </div>\n\n  <!-- Durées de conservation -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Conservation légale</div>\n    <div class=\"panel-title\">Durées légales de conservation des dossiers RH</div>\n    <p class=\"panel-text\">Les durées de conservation combinent les exigences de la Loi 18-07 (principe de limitation) et les prescriptions légales des autres codes (Code du travail, fiscalité, sécurité sociale). Le DRH doit tenir un registre des traitements mentionnant ces durées.</p>\n    <div style=\"overflow-x:auto;margin-top:12px\">\n      <table class=\"rate-tbl\" style=\"width:100%;border-collapse:collapse\">\n        <thead>\n          <tr style=\"background:var(--navy,#1e3a5f);color:#fff\">\n            <th style=\"text-align:left;padding:10px 12px\">Type de document / donnée</th>\n            <th style=\"text-align:left;padding:10px 12px\">Durée de conservation</th>\n            <th style=\"text-align:left;padding:10px 12px\">Base légale</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td colspan=\"3\" style=\"padding:8px 12px;font-weight:700;color:var(--navy,#1e3a5f);font-size:12px;text-transform:uppercase;letter-spacing:.05em\">Documents contractuels</td></tr>\n          <tr><td style=\"padding:9px 12px\">Contrat de travail (CDI/CDD)</td><td style=\"padding:9px 12px\"><strong>5 ans</strong> après fin du contrat</td><td style=\"padding:9px 12px\">Loi n°90-11 · Art. 2271 Code civil</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Avenants et modifications de contrat</td><td style=\"padding:9px 12px\"><strong>5 ans</strong> après fin du contrat</td><td style=\"padding:9px 12px\">Loi n°90-11</td></tr>\n          <tr><td style=\"padding:9px 12px\">Documents d'embauche (CV, diplômes)</td><td style=\"padding:9px 12px\"><strong>2 ans</strong> après fin de relation de travail</td><td style=\"padding:9px 12px\">Loi n°18-07 Art. 14</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td colspan=\"3\" style=\"padding:8px 12px;font-weight:700;color:var(--navy,#1e3a5f);font-size:12px;text-transform:uppercase;letter-spacing:.05em\">Paie &amp; Fiscalité</td></tr>\n          <tr><td style=\"padding:9px 12px\">Bulletins de paie</td><td style=\"padding:9px 12px\"><strong>10 ans</strong></td><td style=\"padding:9px 12px\">Art. 40 CIDTA · Loi n°83-11</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Déclarations DAS (fiscales)</td><td style=\"padding:9px 12px\"><strong>10 ans</strong></td><td style=\"padding:9px 12px\">Art. 75 à 79 CIDTA</td></tr>\n          <tr><td style=\"padding:9px 12px\">Déclarations DAC (CNAS)</td><td style=\"padding:9px 12px\"><strong>10 ans</strong></td><td style=\"padding:9px 12px\">Loi n°83-14 · Ord. n°95-01</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Registres de paie</td><td style=\"padding:9px 12px\"><strong>10 ans</strong></td><td style=\"padding:9px 12px\">Loi n°90-11 Art. 93</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td colspan=\"3\" style=\"padding:8px 12px;font-weight:700;color:var(--navy,#1e3a5f);font-size:12px;text-transform:uppercase;letter-spacing:.05em\">Discipline &amp; Sanctions</td></tr>\n          <tr><td style=\"padding:9px 12px\">Sanctions disciplinaires (avertissements)</td><td style=\"padding:9px 12px\"><strong>3 ans</strong> (puis purge du dossier si aucune récidive)</td><td style=\"padding:9px 12px\">Loi n°90-11 Art. 73 · Loi n°18-07</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Dossiers de licenciement</td><td style=\"padding:9px 12px\"><strong>5 ans</strong> (délai de prescription judiciaire)</td><td style=\"padding:9px 12px\">Art. 2271 Code civil algérien</td></tr>\n          <tr><td style=\"padding:9px 12px\">PV d'audition disciplinaire</td><td style=\"padding:9px 12px\"><strong>5 ans</strong></td><td style=\"padding:9px 12px\">Loi n°90-11 · Loi n°18-07</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td colspan=\"3\" style=\"padding:8px 12px;font-weight:700;color:var(--navy,#1e3a5f);font-size:12px;text-transform:uppercase;letter-spacing:.05em\">Santé &amp; Sécurité</td></tr>\n          <tr><td style=\"padding:9px 12px\">Dossiers médicaux (médecine du travail)</td><td style=\"padding:9px 12px\"><strong>Durée de la vie professionnelle + 5 ans</strong></td><td style=\"padding:9px 12px\">Décret exécutif n°93-120</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Déclarations d'accidents du travail</td><td style=\"padding:9px 12px\"><strong>10 ans</strong></td><td style=\"padding:9px 12px\">Loi n°83-13 · Loi n°88-07</td></tr>\n          <tr><td style=\"padding:9px 12px\">Registre des AT/MP</td><td style=\"padding:9px 12px\"><strong>5 ans</strong></td><td style=\"padding:9px 12px\">Décret exécutif n°05-09</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td colspan=\"3\" style=\"padding:8px 12px;font-weight:700;color:var(--navy,#1e3a5f);font-size:12px;text-transform:uppercase;letter-spacing:.05em\">Formation &amp; Évaluation</td></tr>\n          <tr><td style=\"padding:9px 12px\">Plans et bilans de formation</td><td style=\"padding:9px 12px\"><strong>5 ans</strong></td><td style=\"padding:9px 12px\">Décret n°05-490 · Loi n°18-07</td></tr>\n          <tr style=\"background:var(--surface2,#f8fafc)\"><td style=\"padding:9px 12px\">Grilles d'entretien annuel</td><td style=\"padding:9px 12px\"><strong>5 ans</strong></td><td style=\"padding:9px 12px\">Loi n°18-07 Art. 14</td></tr>\n          <tr><td style=\"padding:9px 12px\">Candidatures non retenues</td><td style=\"padding:9px 12px\"><strong>1 an maximum</strong> après réponse négative</td><td style=\"padding:9px 12px\">Loi n°18-07 Art. 14</td></tr>\n        </tbody>\n      </table>\n    </div>\n    <div class=\"panel-note\" style=\"margin-top:12px\">⚠️ <strong>Note :</strong> Ces durées correspondent aux minimums légaux de prescription ou aux obligations documentaires identifiées. En cas de litige en cours, les documents concernés doivent être conservés jusqu'à la clôture définitive de la procédure, quelle que soit la durée théorique.</div>\n  </div>\n\n  <!-- Droits du salarié -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Droits des personnes</div>\n    <div class=\"panel-title\">Droits du salarié sur ses données personnelles</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>📋 Droit d'accès</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Tout salarié peut demander à consulter l'ensemble des données le concernant détenues par l'employeur (dossier RH, évaluations, données de paie). L'employeur doit répondre dans un <strong>délai raisonnable</strong>. Il peut demander une copie. Ce droit s'exerce auprès du DRH désigné responsable du traitement.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>✏️ Droit de rectification</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Le salarié peut exiger la <strong>correction de toute donnée inexacte ou incomplète</strong> le concernant (état civil, adresse, diplômes, historique de postes). L'employeur est tenu d'effectuer la rectification sans délai et d'en informer les tiers éventuels à qui les données ont été communiquées.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🗑️ Droit à l'effacement</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Le salarié peut demander la <strong>suppression de données</strong> qui ne sont plus nécessaires à la finalité initiale, ou dont la conservation n'est plus justifiée légalement. Ce droit est limité par les obligations de conservation légales (paie, déclarations fiscales et sociales).</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🚫 Droit d'opposition</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Le salarié peut s'opposer au traitement de ses données à des fins de <strong>prospection commerciale interne, de profilage non lié à l'exécution du contrat</strong>, ou de communication à des tiers non prévus. L'opposition à des traitements nécessaires à l'exécution du contrat n'est pas possible.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📢 Droit à l'information</h3>\n        <p style=\"font-size:13px;line-height:1.7\">Avant tout traitement, le salarié doit être <strong>informé</strong> : identité du responsable, finalité du traitement, données collectées, destinataires, durée de conservation, droits exercables et voies de recours. Cette information figure idéalement dans le contrat de travail ou une notice annexée.</p>\n      </div>\n      <div class=\"rh-card\">\n        <h3>⚖️ Droit de recours</h3>\n        <p style=\"font-size:13px;line-height:1.7\">En cas de violation de ses droits, le salarié peut saisir l'<strong>Autorité de Protection des Données Personnelles (APDP)</strong> créée par la Loi n°18-07, ou le tribunal compétent. L'APDP peut ordonner des mesures correctives et infliger des sanctions à l'employeur défaillant.</p>\n      </div>\n    </div>\n  </div>\n\n  <!-- SIRH & bonnes pratiques -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">SIRH &amp; Conformité</div>\n    <div class=\"panel-title\">Règles de confidentialité du SIRH &amp; bonnes pratiques RH</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>🔐 Gestion des accès SIRH</h3>\n        <ul style=\"font-size:13px;line-height:1.9\">\n          <li>Attribuer des <strong>profils d'habilitation</strong> nominatifs et différenciés selon le rôle (RH, manager, paie, direction).</li>\n          <li>Principe du <strong>moindre privilège</strong> : chaque utilisateur n'accède qu'aux données nécessaires à ses missions.</li>\n          <li>Révoquer immédiatement les accès lors de tout départ ou changement de poste.</li>\n          <li>Activer les <strong>journaux d'audit (logs)</strong> pour tracer les accès et modifications.</li>\n          <li>Imposer des <strong>mots de passe forts</strong> et le renouvellement périodique (ou authentification à deux facteurs).</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📁 Sécurité des dossiers physiques</h3>\n        <ul style=\"font-size:13px;line-height:1.9\">\n          <li>Conserver les dossiers physiques dans des <strong>armoires fermées à clé</strong>, accessibles uniquement au personnel RH autorisé.</li>\n          <li>Ne jamais laisser de dossiers individuels accessibles dans des espaces partagés.</li>\n          <li>Utiliser des <strong>enveloppes scellées</strong> pour les documents sensibles (bulletins, évaluations) remis en main propre.</li>\n          <li>Détruire les documents périmés par <strong>déchiquetage sécurisé</strong> (ne pas jeter en poubelle ordinaire).</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📧 Communications et transferts</h3>\n        <ul style=\"font-size:13px;line-height:1.9\">\n          <li>Ne jamais envoyer de données RH sensibles (bulletins, dossiers médicaux) par e-mail non sécurisé.</li>\n          <li>Utiliser des canaux <strong>chiffrés ou des plateformes sécurisées</strong> pour partager des fichiers RH.</li>\n          <li>Toute communication de données à un tiers (expert-comptable, avocat, organisme social) doit être encadrée par un <strong>accord de confidentialité</strong> ou une clause contractuelle.</li>\n          <li>Les transferts hors Algérie de données RH sont soumis à <strong>autorisation préalable de l'APDP</strong> (Art. 51 Loi n°18-07).</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🏥 Données de santé — régime spécial</h3>\n        <ul style=\"font-size:13px;line-height:1.9\">\n          <li>Les données de santé sont des <strong>données sensibles</strong> soumises à un régime de protection renforcé (Art. 26 Loi n°18-07).</li>\n          <li>Seul le <strong>médecin du travail</strong> peut traiter les données médicales détaillées. L'employeur ne reçoit que les conclusions d'aptitude ou d'inaptitude.</li>\n          <li>Un arrêt maladie justifie la connaissance de la durée d'absence, non du diagnostic.</li>\n          <li>Toute collecte de données de santé non justifiée médicalement est interdite.</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Sanctions -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Sanctions</div>\n    <div class=\"panel-title\">Sanctions en cas de manquement — Loi n°18-07 &amp; Code pénal</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\" style=\"border-left:3px solid var(--amber,#d97706)\">\n        <h3>⚠️ Sanctions administratives (APDP)</h3>\n        <ul style=\"font-size:13px;line-height:1.9\">\n          <li><strong>Avertissement formel</strong> avec mise en demeure de mise en conformité.</li>\n          <li><strong>Injonction de cesser</strong> le traitement non conforme.</li>\n          <li><strong>Amende administrative</strong> dont le montant est fixé par la Loi n°18-07 (Art. 65 et s.) — consultez la version consolidée pour les montants actualisés.</li>\n          <li>Publication de la sanction (name &amp; shame) dans les cas graves.</li>\n          <li>Suspension ou interdiction temporaire du traitement des données.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\" style=\"border-left:3px solid #dc2626\">\n        <h3>🚨 Sanctions pénales (Code pénal)</h3>\n        <ul style=\"font-size:13px;line-height:1.9\">\n          <li><strong>Collecte illicite de données personnelles</strong> : emprisonnement de 3 mois à 1 an et/ou amende (Art. 303 bis et s. Code pénal).</li>\n          <li><strong>Divulgation non autorisée</strong> de données à caractère personnel : peines similaires aggravées selon la nature des données.</li>\n          <li><strong>Atteinte au secret professionnel</strong> (données médicales, judiciaires) : peines spécifiques prévues par le Code pénal.</li>\n          <li>La responsabilité pénale concerne <strong>les personnes physiques</strong> (DRH, dirigeant) et peut être engagée parallèlement aux sanctions administratives.</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"panel-note\" style=\"margin-top:12px\">📌 <strong>Recommandation DRH :</strong> Désignez un <strong>Responsable de la Protection des Données (RPD)</strong> en interne ou externalisé, tenant à jour un registre des traitements RH et assurant la veille réglementaire. Déclarez vos traitements sensibles auprès de l'APDP conformément à l'Art. 23 de la Loi n°18-07.</div>\n  </div>\n\n  <!-- Checklist conformité -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Auto-évaluation</div>\n    <div class=\"panel-title\">Checklist de conformité Loi 18-07 pour le DRH</div>\n    <div style=\"background:var(--surface2,#f8fafc);border:1px solid var(--border,#e2e8f0);border-radius:10px;padding:16px\">\n      <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;flex-wrap:wrap;gap:10px\">\n        <strong style=\"font-size:14px\">🔒 Conformité Protection des Données RH</strong>\n        <button onclick=\"copyChecklistData()\" style=\"background:var(--teal,#0d9488);color:#fff;border:none;border-radius:6px;padding:6px 14px;font-size:12px;cursor:pointer;font-weight:600\">📋 Copier la checklist</button>\n      </div>\n      <div id=\"checklist-data\" style=\"font-size:13px;line-height:2.1;color:var(--ink-soft,#374151);columns:2;column-gap:24px\">\n        <div>☐ &nbsp;Inventaire des traitements RH réalisé (registre des traitements)</div>\n        <div>☐ &nbsp;Déclaration des traitements sensibles à l'APDP</div>\n        <div>☐ &nbsp;Notice d'information vie privée remise à chaque salarié</div>\n        <div>☐ &nbsp;Durées de conservation définies et respectées par type de document</div>\n        <div>☐ &nbsp;Politique de destruction sécurisée des documents périmés</div>\n        <div>☐ &nbsp;Habilitations SIRH limitées au principe du moindre privilège</div>\n        <div>☐ &nbsp;Logs d'accès au SIRH activés et conservés</div>\n        <div>☐ &nbsp;Procédure de gestion des droits (accès, rectification, effacement) documentée</div>\n        <div>☐ &nbsp;Clause de confidentialité dans les contrats de travail</div>\n        <div>☐ &nbsp;Accords de confidentialité avec les prestataires RH externes</div>\n        <div>☐ &nbsp;Données de santé traitées exclusivement par le médecin du travail</div>\n        <div>☐ &nbsp;Sécurisation des dossiers physiques (armoires fermées)</div>\n        <div>☐ &nbsp;Formation du personnel RH aux obligations Loi 18-07</div>\n        <div>☐ &nbsp;Responsable de la Protection des Données (RPD) désigné</div>\n        <div>☐ &nbsp;Procédure de notification de violation de données définie</div>\n        <div>☐ &nbsp;Transferts de données hors Algérie autorisés par l'APDP si applicables</div>\n      </div>\n    </div>\n  </div>",
  "theme13": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Thème 13 — Priorité 2</div>\n    <div class=\"panel-title\">🌍 Travail des étrangers &amp; Mobilité internationale</div>\n    <p class=\"panel-text\">L'emploi de ressortissants étrangers en Algérie est strictement encadré par le droit du travail algérien. L'employeur doit respecter une procédure d'autorisation préalable, des quotas sectoriels et des obligations déclaratives spécifiques. Parallèlement, les entreprises algériennes envoyant des salariés à l'étranger (expatriés sortants) ou les sociétés étrangères opérant en Algérie (établissements stables, joint-ventures) font face à des enjeux fiscaux et de sécurité sociale particuliers.</p>\n    <div class=\"panel-note\">📌 <strong>Sources juridiques :</strong> Décret exécutif n°03-251 du 19/07/2003 (emploi étrangers) · Décret exécutif n°06-154 du 05/05/2006 (conditions emploi travailleurs étrangers) · Loi n°90-11 Art. 6, 7, 17, 18 · CIDTA Art. 66-68 (IRG non-résidents) · Convention de Vienne · Conventions bilatérales de sécurité sociale (Algérie-France, Algérie-Tunisie, etc.) · Ordonnance n°01-03 du 20/08/2001 (investissement étranger)</div>\n  </div>\n\n  <!-- Permis de travail -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Autorisation légale</div>\n    <div class=\"panel-title\">📋 Permis de travail — Conditions &amp; Procédure</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>⚖️ Principe légal &amp; quotas</h3>\n        <ul>\n          <li><strong>Principe :</strong> Tout ressortissant étranger souhaitant exercer une activité salariée en Algérie doit détenir une <strong>autorisation de travail</strong> délivrée par le Ministère du Travail (MTESS), préalablement à son recrutement.</li>\n          <li><strong>Quota :</strong> Le nombre de travailleurs étrangers est plafonné à <strong>20 % de l'effectif total</strong> dans la plupart des secteurs (Décret n°06-154). Des dérogations peuvent être accordées pour des compétences rares non disponibles localement.</li>\n          <li><strong>Priorité nationale :</strong> L'employeur doit justifier de l'impossibilité de pourvoir le poste avec un travailleur algérien avant tout recrutement étranger (recherche via ANEM obligatoire).</li>\n          <li><strong>Durée :</strong> L'autorisation est accordée pour la durée du contrat, renouvelable. Elle est nominative et liée à l'employeur.</li>\n          <li><strong>Sanction :</strong> L'emploi d'un étranger sans autorisation expose l'employeur à des amendes et poursuites pénales (Art. 10 Décret n°06-154).</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>📁 Dossier de demande d'autorisation</h3>\n        <ul>\n          <li>Demande adressée à la Direction de l'Emploi de la Wilaya compétente (relevant du MTESS).</li>\n          <li><strong>Pièces requises (employeur) :</strong> Extrait de registre de commerce · Bilan social ou état de l'effectif · Justification du besoin (fiche de poste, tentatives de recrutement local infructueuses) · Engagement à rapatrier l'étranger à la fin du contrat.</li>\n          <li><strong>Pièces requises (travailleur étranger) :</strong> Passeport valide · Diplômes et qualifications authentifiés · CV · Extrait de casier judiciaire du pays d'origine · Certificat médical.</li>\n          <li><strong>Visa de travail :</strong> Obtenu auprès du consulat algérien à l'étranger, sur présentation de l'autorisation de travail délivrée par le MTESS.</li>\n          <li><strong>Carte de séjour :</strong> Délivrée par la DGSN après entrée régulière sur le territoire. À renouveler annuellement.</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"panel-note\" style=\"margin-top:10px\">⚠️ <strong>Cas particuliers exemptés :</strong> Certaines catégories peuvent bénéficier de régimes allégés — experts détachés dans le cadre d'un marché public (accord gouvernemental), personnel d'ambassades et organisations internationales (Convention de Vienne), ressortissants de pays avec lesquels l'Algérie a signé des accords de main-d'œuvre. Vérifier au cas par cas auprès du MTESS.</div>\n  </div>\n\n  <!-- Contrat expatrié -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Contrat &amp; statuts</div>\n    <div class=\"panel-title\">📄 Contrat du travailleur expatrié &amp; statuts possibles</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>📑 Les 3 formes de mise à disposition</h3>\n        <ul>\n          <li><strong>1. Contrat local algérien :</strong> L'étranger signe un contrat de droit algérien directement avec l'entreprise algérienne. Il est soumis à la Loi n°90-11, aux cotisations CNAS et à l'IRG algérien comme tout salarié local. La rémunération doit être au moins égale au SNMG.</li>\n          <li><strong>2. Détachement :</strong> L'étranger reste salarié de son employeur d'origine (à l'étranger) et est mis à disposition de l'entité algérienne pour une durée limitée. Il conserve son contrat d'origine et peut maintenir sa couverture sociale d'origine si une convention bilatérale l'y autorise.</li>\n          <li><strong>3. Contrat international :</strong> Contrat hybride avec une partie locale et une partie internationale (split payroll). Utilisé par les multinationales pour les cadres expatriés à haut niveau de rémunération. Complexe sur le plan fiscal et social — nécessite un conseil spécialisé.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>💼 Clauses spécifiques au contrat expatrié</h3>\n        <ul>\n          <li><strong>Langue :</strong> Le contrat peut être rédigé en arabe ou en français (langue de travail admise). Si en langue étrangère uniquement, une traduction en arabe est fortement recommandée.</li>\n          <li><strong>Rémunération :</strong> Préciser la devise de paiement (DA ou devise étrangère si autorisé). Les paiements en devises en Algérie sont soumis à la réglementation de la Banque d'Algérie.</li>\n          <li><strong>Logement &amp; frais de vie :</strong> Les indemnités d'expatriation (logement, scolarité des enfants, billet retour annuel) doivent être précisées. Leur régime fiscal varie selon leur nature (remboursement de frais réels vs avantage en nature).</li>\n          <li><strong>Rapatriement :</strong> L'employeur algérien est légalement tenu d'assurer le retour du salarié étranger dans son pays à la fin du contrat (Décret n°06-154).</li>\n          <li><strong>Résiliation :</strong> Mêmes règles que pour un salarié algérien (préavis, procédure disciplinaire si faute). L'expulsion du territoire ne peut se substituer à la procédure légale de licenciement.</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Fiscalité IRG non-résidents -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Fiscalité IRG</div>\n    <div class=\"panel-title\">💰 Fiscalité IRG — Travailleurs étrangers en Algérie</div>\n    <p class=\"panel-text\">La fiscalité d'un travailleur étranger en Algérie dépend principalement de sa <strong>résidence fiscale</strong> et de l'existence d'une <strong>convention fiscale bilatérale</strong> entre l'Algérie et son pays d'origine.</p>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>🏠 Résident fiscal algérien</h3>\n        <ul>\n          <li><strong>Critère :</strong> Séjour en Algérie de plus de <strong>183 jours</strong> sur une période de 12 mois, ou foyer permanent en Algérie, ou centre des intérêts économiques en Algérie (Art. 2 CIDTA).</li>\n          <li><strong>Régime :</strong> Soumis à l'IRG sur <strong>l'ensemble de ses revenus mondiaux</strong> de source algérienne selon le barème progressif (Art. 104 CIDTA), comme tout salarié algérien.</li>\n          <li><strong>Abattement :</strong> Bénéficie du même abattement de 40 % (min 1 000 DA / max 1 500 DA/mois) que les résidents.</li>\n          <li><strong>Obligations :</strong> L'employeur effectue la retenue à la source mensuelle. Le salarié peut être tenu à une déclaration annuelle si revenus multiples.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>✈️ Non-résident fiscal</h3>\n        <ul>\n          <li><strong>Critère :</strong> Séjour inférieur à 183 jours, pas de foyer permanent en Algérie.</li>\n          <li><strong>Régime de droit commun :</strong> IRG retenu à la source au <strong>taux libératoire de 20 %</strong> sur les revenus de source algérienne (Art. 107 CIDTA) — sauf convention fiscale contraire.</li>\n          <li><strong>Conventions bilatérales :</strong> L'Algérie a signé des conventions fiscales avec notamment la France, la Tunisie, le Maroc, l'Espagne, la Belgique, l'Italie, la Chine, etc. Ces conventions peuvent réduire ou éliminer la double imposition. Vérifier la convention applicable cas par cas.</li>\n          <li><strong>Attestation de résidence fiscale :</strong> Le travailleur étranger doit produire une attestation de résidence fiscale de son pays d'origine pour bénéficier du régime conventionnel.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🏢 Sociétés étrangères opérant en Algérie</h3>\n        <ul>\n          <li><strong>Établissement stable :</strong> Une société étrangère qui exerce une activité en Algérie de manière habituelle (chantier, bureau de représentation, agent dépendant) constitue un établissement stable soumis à l'IBS (Impôt sur les Bénéfices des Sociétés) algérien.</li>\n          <li><strong>Joint-venture / filiale :</strong> Soumise à toutes les obligations du droit algérien (Loi n°90-11, CNAS, IRG, IBS) comme toute entreprise de droit algérien.</li>\n          <li><strong>Retenues à la source sur prestations :</strong> Les honoraires versés à une société étrangère non établie en Algérie sont soumis à une retenue à la source de <strong>24 % sur le brut HT</strong> (Art. 150 CIDTA), sauf convention fiscale.</li>\n          <li><strong>Rapatriement des bénéfices :</strong> Encadré par la réglementation des changes de la Banque d'Algérie. Requiert l'approbation de la COSOB/MF pour certaines opérations.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🌐 Avantages en nature &amp; indemnités d'expatriation</h3>\n        <ul>\n          <li><strong>Logement de fonction :</strong> Avantage en nature cotisable (CNAS) et imposable (IRG) selon la valeur locative réelle ou forfaitaire.</li>\n          <li><strong>Scolarité des enfants :</strong> Prise en charge admise en charge déductible pour l'employeur si justifiée. Régime IRG à vérifier selon que c'est un remboursement de frais réels ou un avantage.</li>\n          <li><strong>Billet retour annuel :</strong> Remboursement de frais réels, non imposable si dans des limites raisonnables et justifié.</li>\n          <li><strong>Prime d'expatriation :</strong> Soumise à l'IRG dans les conditions de droit commun (après abattement). Non exonérée en droit algérien sauf disposition conventionnelle contraire.</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Sécurité sociale internationale -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Sécurité sociale</div>\n    <div class=\"panel-title\">🏥 Sécurité sociale internationale &amp; Conventions bilatérales</div>\n    <div class=\"grid-2\">\n      <div class=\"rh-card\">\n        <h3>📋 Principe de territorialité CNAS</h3>\n        <ul>\n          <li><strong>Règle générale :</strong> Tout salarié travaillant sur le territoire algérien — quelle que soit sa nationalité — est affilié à la <strong>CNAS</strong> et cotise aux taux légaux (9 % salarié / 26 % patronal sur l'assiette CNAS).</li>\n          <li><strong>Branches couvertes :</strong> Maladie-maternité, AT/MP, invalidité, décès, retraite (CNR), chômage (CNAC).</li>\n          <li><strong>Droit aux prestations :</strong> Le travailleur étranger cotisant à la CNAS bénéficie des mêmes prestations qu'un travailleur algérien (remboursements médicaux, indemnités journalières, pension en cas de droit acquis).</li>\n          <li><strong>Difficulté pratique :</strong> En l'absence de convention bilatérale, le travailleur étranger peut être doublement cotisant (pays d'origine + Algérie) et ne pas pouvoir cumuler les droits à retraite. C'est le problème de la double cotisation.</li>\n        </ul>\n      </div>\n      <div class=\"rh-card\">\n        <h3>🤝 Conventions bilatérales de sécurité sociale</h3>\n        <ul>\n          <li><strong>Objet :</strong> Éviter la double cotisation et permettre la <strong>totalisation des périodes</strong> d'assurance pour le calcul des droits à retraite.</li>\n          <li><strong>Algérie-France :</strong> Convention bilatérale en vigueur permettant la coordination des régimes. Un salarié français détaché peut rester affilié à la sécurité sociale française sous conditions (certificat de détachement A1 ou équivalent).</li>\n          <li><strong>Algérie-Tunisie &amp; Maroc :</strong> Conventions Maghreb de sécurité sociale facilitant la mobilité intra-régionale.</li>\n          <li><strong>Autres pays :</strong> Vérifier l'existence d'une convention bilatérale auprès du MTESS ou de l'ambassade concernée. En l'absence de convention, la double cotisation s'applique.</li>\n          <li><strong>Certificat de détachement :</strong> Document émis par l'organisme de sécurité sociale du pays d'origine, attestant que le salarié reste couvert dans son régime d'origine pendant la période de détachement en Algérie.</li>\n        </ul>\n      </div>\n    </div>\n  </div>\n\n  <!-- Checklist employeur -->\n  <div class=\"panel\">\n    <div class=\"panel-kicker\">Processus RH</div>\n    <div class=\"panel-title\">✅ Checklist employeur — Recrutement d'un salarié étranger</div>\n    <div style=\"background:var(--surface2,#f8fafc);border:1px solid var(--border,#e2e8f0);border-radius:10px;padding:16px\">\n      <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;flex-wrap:wrap;gap:10px\">\n        <strong style=\"font-size:14px\">🌍 Checklist — Embauche travailleur étranger</strong>\n        <button onclick=\"copyChecklistEtranger()\" style=\"background:var(--teal,#0d9488);color:#fff;border:none;border-radius:6px;padding:6px 14px;font-size:12px;cursor:pointer;font-weight:600\">📋 Copier</button>\n      </div>\n      <div id=\"checklist-etranger\" style=\"font-size:13px;line-height:2.1;color:var(--ink-soft,#374151)\">\n        <div style=\"font-weight:700;color:var(--navy,#1e3a5f);margin-top:4px\">AVANT L'EMBAUCHE</div>\n        <div>☐ &nbsp;Vérification du quota (≤ 20 % de l'effectif) — Décret n°06-154</div>\n        <div>☐ &nbsp;Recherche infructueuse de candidats algériens documentée (ANEM)</div>\n        <div>☐ &nbsp;Dépôt de la demande d'autorisation de travail à la Direction de l'Emploi (Wilaya)</div>\n        <div>☐ &nbsp;Obtention de l'autorisation de travail MTESS</div>\n        <div>☐ &nbsp;Visa de travail obtenu auprès du consulat algérien</div>\n        <div style=\"font-weight:700;color:var(--navy,#1e3a5f);margin-top:8px\">À L'EMBAUCHE</div>\n        <div>☐ &nbsp;Contrat de travail rédigé et signé (droit algérien ou détachement selon statut)</div>\n        <div>☐ &nbsp;Vérification passeport valide + visa travail en cours de validité</div>\n        <div>☐ &nbsp;Affiliation CNAS dès le 1er jour de travail</div>\n        <div>☐ &nbsp;Déclaration à l'ANEM dans les 30 jours suivant l'embauche</div>\n        <div>☐ &nbsp;Vérification existence convention bilatérale SS (si détachement)</div>\n        <div>☐ &nbsp;Certificat de détachement SS si convention applicable</div>\n        <div style=\"font-weight:700;color:var(--navy,#1e3a5f);margin-top:8px\">PENDANT L'EMPLOI</div>\n        <div>☐ &nbsp;Suivi renouvellement titre de séjour (DGSN) + autorisation de travail (annuel)</div>\n        <div>☐ &nbsp;Déclarations mensuelles CNAS et retenues IRG correctement effectuées</div>\n        <div>☐ &nbsp;Vérification conventionnelle si revenu dépasse seuil nécessitant déclaration fiscale</div>\n        <div style=\"font-weight:700;color:var(--navy,#1e3a5f);margin-top:8px\">À LA FIN DU CONTRAT</div>\n        <div>☐ &nbsp;Remise des documents de sortie (STC, certificat de travail, attestation CNAS)</div>\n        <div>☐ &nbsp;Rapatriement assuré par l'employeur (obligation légale)</div>\n        <div>☐ &nbsp;Déclaration de sortie CNAS</div>\n        <div>☐ &nbsp;Radiation auprès de la Direction de l'Emploi</div>\n      </div>\n    </div>\n\n    <div class=\"panel-note\" style=\"margin-top:12px\">⚠️ <strong>Conseil DRH :</strong> La réglementation sur l'emploi des étrangers évolue régulièrement (circulaires ministérielles, modifications de décrets). Consultez systématiquement la Direction de l'Emploi de votre wilaya et le MTESS avant tout recrutement étranger. Les textes d'application peuvent introduire des exigences supplémentaires non listées ici.</div>\n  </div>",
  "faq": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Outil transverse — Priorité 3</div>\n    <div class=\"panel-title\">❓ FAQ RH — Questions &amp; réponses rapides</div>\n    <p class=\"panel-text\">Réponses courtes et directes aux questions les plus fréquentes posées par les managers, salariés et chefs d'entreprise. Chaque réponse renvoie au thème du guide pour approfondir. Ces réponses sont données à titre indicatif — consultez un juriste pour toute situation à enjeu.</p>\n    <div class=\"toolbar\" style=\"margin-bottom:14px\">\n      <div class=\"search-wrap\" style=\"flex:1;min-width:220px\">\n        <span class=\"search-icon\">🔍</span>\n        <input type=\"text\" id=\"faq-srch\" placeholder=\"Rechercher une question…\" oninput=\"faqFilter()\">\n      </div>\n      <div style=\"display:flex;gap:8px;flex-wrap:wrap\">\n        <button class=\"rh-tab active\" onclick=\"faqSetCat('tous',this)\" style=\"font-size:12px;padding:6px 14px\">Toutes</button>\n        <button class=\"rh-tab\" onclick=\"faqSetCat('contrat',this)\" style=\"font-size:12px;padding:6px 14px\">📑 Contrat</button>\n        <button class=\"rh-tab\" onclick=\"faqSetCat('paie',this)\" style=\"font-size:12px;padding:6px 14px\">💰 Paie</button>\n        <button class=\"rh-tab\" onclick=\"faqSetCat('conges',this)\" style=\"font-size:12px;padding:6px 14px\">🏖️ Congés</button>\n        <button class=\"rh-tab\" onclick=\"faqSetCat('discipline',this)\" style=\"font-size:12px;padding:6px 14px\">⚖️ Discipline</button>\n        <button class=\"rh-tab\" onclick=\"faqSetCat('sante',this)\" style=\"font-size:12px;padding:6px 14px\">🏥 Santé</button>\n        <button class=\"rh-tab\" onclick=\"faqSetCat('retraite',this)\" style=\"font-size:12px;padding:6px 14px\">🎯 Retraite</button>\n        <button class=\"rh-tab\" onclick=\"faqSetCat('divers',this)\" style=\"font-size:12px;padding:6px 14px\">📌 Divers</button>\n      </div>\n      <span id=\"faq-count\" style=\"align-self:center;font-size:13px;color:var(--muted)\">— questions</span>\n    </div>\n    <div id=\"faq-grid\" style=\"display:flex;flex-direction:column;gap:10px\"></div>\n    <div id=\"faq-nores\" style=\"display:none;text-align:center;padding:32px;color:var(--muted)\">Aucune question trouvée.</div>\n  </div>",
  "dico": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Outil transverse</div>\n    <div class=\"panel-title\">📖 Dictionnaire RH — Termes &amp; Acronymes</div>\n    <p class=\"panel-text\">Retrouvez ici les définitions des termes RH internationaux couramment utilisés et des acronymes/sigles juridiques algériens. Chaque entrée précise la définition, le thème du guide concerné et la référence légale lorsqu'elle existe.</p>\n  </div>\n\n  <!-- Barre de recherche et filtres -->\n  <div class=\"toolbar\" style=\"flex-wrap:wrap;gap:10px;margin-bottom:14px\">\n    <div class=\"search-wrap\" style=\"flex:1;min-width:220px\">\n      <span class=\"search-icon\">🔍</span>\n      <input type=\"text\" id=\"dico-srch\" placeholder=\"Rechercher un terme, un acronyme, une loi…\" oninput=\"dicoFilter()\">\n    </div>\n    <div style=\"display:flex;gap:8px;flex-wrap:wrap\">\n      <button class=\"rh-tab active\" onclick=\"dicoSetCat('tous',this)\" style=\"font-size:12px;padding:6px 14px\">Tous</button>\n      <button class=\"rh-tab\" onclick=\"dicoSetCat('international',this)\" style=\"font-size:12px;padding:6px 14px\">🌐 Termes RH</button>\n      <button class=\"rh-tab\" onclick=\"dicoSetCat('algerie',this)\" style=\"font-size:12px;padding:6px 14px\">🇩🇿 Acronymes DZ</button>\n    </div>\n    <span class=\"count-rhBadge\" id=\"dico-count\" style=\"align-self:center\">— termes</span>\n  </div>\n\n  <!-- Filtre alphabétique -->\n  <div id=\"dico-alpha\" style=\"display:flex;flex-wrap:wrap;gap:4px;margin-bottom:14px\">\n  </div>\n\n  <!-- Grille de cartes -->\n  <div id=\"dico-grid\" style=\"display:grid;grid-template-columns:repeat(auto-fill,minmax(310px,1fr));gap:14px;margin-top:4px\"></div>\n  <div id=\"dico-nores\" style=\"display:none;text-align:center;padding:32px;color:var(--muted)\">Aucun terme trouvé. Essayez une autre recherche.</div>",
  "modeles": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Outil transverse</div>\n    <div class=\"panel-title\">📄 Modèles &amp; Documents types</div>\n    <p class=\"panel-text\">9 modèles prêts à l'emploi conformes au droit du travail algérien. Cliquez sur <strong>📋 Copier</strong> pour copier le texte dans votre presse-papier, puis collez-le dans votre traitement de texte. Personnalisez les champs entre crochets <code>[…]</code> avant utilisation.</p>\n    <div class=\"panel-note\">⚠️ <strong>Avertissement :</strong> Ces modèles sont fournis à titre indicatif. Adaptez-les à votre convention collective, règlement intérieur et situation particulière. Pour les actes à enjeu (licenciement pour faute grave, mise à pied), consultez un juriste ou l'inspection du travail.</div>\n  </div>\n\n  <!-- Sous-navigation modèles -->\n  <div class=\"rh-tab-bar\" style=\"margin-bottom:0\">\n    <button class=\"rh-tab active\" onclick=\"modShowTab('contrats',this)\">📑 Contrats</button>\n    <button class=\"rh-tab\" onclick=\"modShowTab('discipline',this)\">⚖️ Discipline &amp; Rupture</button>\n    <button class=\"rh-tab\" onclick=\"modShowTab('attestations',this)\">📋 Attestations</button>\n    <button class=\"rh-tab\" onclick=\"modShowTab('evaluation',this)\">🎯 Évaluation &amp; RI</button>\n  </div>\n\n  <!-- ── CONTRATS ──────────────────────────────── -->\n  <div id=\"tab-mod-contrats\">\n\n    <!-- CDI -->\n    <div class=\"panel\" style=\"margin-top:14px\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 1</div><div class=\"panel-title\" style=\"margin:0\">Contrat de travail à durée indéterminée (CDI)</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-cdi')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Base légale : Loi n°90-11 du 21/04/1990 — Art. 11 à 23</div>\n      <pre id=\"mod-cdi\" class=\"mod-pre\">CONTRAT DE TRAVAIL À DURÉE INDÉTERMINÉE (CDI)\n\nEntre les soussignés :\n\nL'EMPLOYEUR\nDénomination : [Raison sociale de l'entreprise]\nForme juridique : [SARL / SPA / EURL / …]\nAdresse du siège : [Adresse complète]\nNIF : [Numéro d'identification fiscale]\nAffiliation CNAS n° : [Numéro d'affiliation]\nReprésenté(e) par : [Nom, Prénom], agissant en qualité de [Fonction],\nci-après dénommé « l'Employeur »,\n\nD'UNE PART,\n\nET\n\nLE SALARIÉ\nNom et prénom : [Nom, Prénom]\nDate de naissance : [JJ/MM/AAAA]\nLieu de naissance : [Commune, Wilaya]\nN° CNI : [Numéro de la carte nationale d'identité]\nAdresse : [Adresse complète]\nci-après dénommé « le Salarié »,\n\nD'AUTRE PART,\n\nIL A ÉTÉ CONVENU CE QUI SUIT :\n\nArticle 1 — Engagement\nL'Employeur engage le Salarié à compter du [JJ/MM/AAAA] pour une durée indéterminée,\npour exercer la fonction de [Intitulé du poste] au sein de [Département / Service].\n\nArticle 2 — Période d'essai\nLe présent contrat est soumis à une période d'essai de [durée] conformément\nà la convention collective applicable et aux dispositions de l'Art. 17 de la Loi n°90-11.\nDurant cette période, chaque partie peut rompre le contrat sans préavis ni indemnité.\n\nArticle 3 — Lieu de travail\nLe Salarié exercera ses fonctions à [Adresse du lieu de travail], sous réserve\ndes nécessités du service pouvant entraîner des déplacements ponctuels.\n\nArticle 4 — Rémunération\nLe Salarié percevra une rémunération mensuelle brute de [montant en chiffres] DA\n([montant en lettres] dinars algériens), décomposée comme suit :\n  - Salaire de base : [montant] DA\n  - IEP (ancienneté) : selon barème légal (Décret n°94-289)\n  - [Autres primes ou indemnités le cas échéant]\n\nArticle 5 — Durée du travail\nLa durée de travail est fixée à [40 ou 44] heures par semaine, conformément\nà la Loi n°90-11 et au règlement intérieur de l'entreprise.\n\nArticle 6 — Congés annuels\nLe Salarié bénéficiera d'un congé annuel payé de 30 jours calendriers minimum\n(Art. 49 à 59 de la Loi n°90-11), augmenté le cas échéant des bonifications\nprévues par la convention collective.\n\nArticle 7 — Obligations du Salarié\nLe Salarié s'engage à :\n  - Exercer ses fonctions avec diligence et loyauté ;\n  - Respecter le règlement intérieur, les instructions de la hiérarchie et les normes HSE ;\n  - Préserver la confidentialité des informations de l'entreprise ;\n  - Ne pas exercer d'activité concurrente sans accord préalable écrit de l'Employeur.\n\nArticle 8 — Convention collective\nLe présent contrat est régi par les dispositions de la Loi n°90-11 du 21/04/1990\net de la convention collective de branche [intitulé] / du règlement intérieur de l'entreprise.\n\nArticle 9 — Litiges\nTout différend relatif à l'exécution ou à l'interprétation du présent contrat sera\nsoumis à la procédure de conciliation prévue par la Loi n°90-11, puis, à défaut\nd'accord, au tribunal compétent.\n\nFait à [Ville], le [JJ/MM/AAAA], en deux (2) exemplaires originaux.\n\nL'Employeur                              Le Salarié\n[Nom, Qualité, Cachet]                   [Nom, Prénom]\n                                          (Mention manuscrite : « Lu et approuvé »)\nSignature :                              Signature :</pre>\n    </div>\n\n    <!-- CDD -->\n    <div class=\"panel\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 2</div><div class=\"panel-title\" style=\"margin:0\">Contrat de travail à durée déterminée (CDD)</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-cdd')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Base légale : Loi n°90-11 Art. 12 · Ordonnance n°96-21 · Le CDD doit impérativement mentionner son motif légal sous peine de requalification en CDI.</div>\n      <pre id=\"mod-cdd\" class=\"mod-pre\">CONTRAT DE TRAVAIL À DURÉE DÉTERMINÉE (CDD)\n\nEntre les soussignés :\n\nL'EMPLOYEUR\nDénomination : [Raison sociale de l'entreprise]\nAdresse : [Adresse complète]\nNIF : [Numéro d'identification fiscale]\nAffiliation CNAS n° : [Numéro d'affiliation]\nReprésenté(e) par : [Nom, Prénom], [Fonction],\n\nD'UNE PART,\n\nET\n\nLE SALARIÉ\nNom et prénom : [Nom, Prénom]\nDate de naissance : [JJ/MM/AAAA]\nN° CNI : [Numéro CNI]\nAdresse : [Adresse complète]\n\nD'AUTRE PART,\n\nIL A ÉTÉ CONVENU CE QUI SUIT :\n\nArticle 1 — Objet et motif du contrat\n[CHOISIR LE MOTIF LÉGAL APPLICABLE — supprimer les autres]\n□ Accroissement temporaire d'activité lié à [description précise]\n□ Remplacement d'un salarié absent nommé [Nom du salarié remplacé], en [congé maladie / maternité / …]\n□ Travaux saisonniers liés à [description de l'activité saisonnière]\n□ Emploi à caractère temporaire par nature (Art. 12 Loi n°90-11)\n\nLe présent contrat est conclu pour le motif susindiqué, conformément à l'Art. 12\nde la Loi n°90-11 du 21/04/1990 modifiée.\n\nArticle 2 — Durée\nLe présent contrat prend effet le [JJ/MM/AAAA] et prend fin le [JJ/MM/AAAA],\nsoit une durée de [X mois / semaines].\n[Si remplacement : « ou au retour effectif de M./Mme [Nom], selon la première échéance. »]\n\nArticle 3 — Poste et lieu de travail\nLe Salarié est engagé en qualité de [Intitulé du poste], affecté au [Service / Département],\ndont le lieu d'exercice est [Adresse].\n\nArticle 4 — Rémunération\nRémunération mensuelle brute : [montant] DA ([montant en lettres] dinars algériens).\nComposée de : Salaire de base [montant] DA + IEP [montant] DA + [autres éléments].\n\nArticle 5 — Durée du travail et congés\nDurée hebdomadaire : [40 ou 44] heures.\nCongés payés : acquis au prorata de la durée du contrat (2,5 jours/mois travaillé).\n\nArticle 6 — Fin du contrat\nÀ l'échéance du terme, le contrat prend fin de plein droit sans qu'il soit nécessaire\nde respecter un préavis (sauf convention collective contraire). Une indemnité de fin\nde contrat peut être due selon la convention collective applicable.\n\nArticle 7 — Renouvellement\nLe présent contrat peut être renouvelé une seule fois pour la même durée, dans\nles conditions fixées par la Loi n°90-11 et la convention collective de branche.\nTout renouvellement au-delà des limites légales entraîne la requalification en CDI.\n\nArticle 8 — Dispositions communes\nLes autres dispositions relatives à la discipline, aux obligations du salarié,\naux congés maladie et à la sécurité sociale sont celles de la Loi n°90-11\net de la convention collective [intitulé] applicable.\n\nFait à [Ville], le [JJ/MM/AAAA], en deux (2) exemplaires originaux.\n\nL'Employeur                              Le Salarié\n[Nom, Qualité, Cachet]                   [Nom, Prénom]\n                                          (Mention manuscrite : « Lu et approuvé »)\nSignature :                              Signature :</pre>\n    </div>\n\n  </div><!-- /tab-mod-contrats -->\n\n  <!-- ── DISCIPLINE & RUPTURE ──────────────────── -->\n  <div id=\"tab-mod-discipline\" style=\"display:none\">\n\n    <!-- Avertissement -->\n    <div class=\"panel\" style=\"margin-top:14px\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 3</div><div class=\"panel-title\" style=\"margin:0\">Lettre d'avertissement</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-avert')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Base légale : Loi n°90-11 Art. 73 (graduation des sanctions) · Règlement intérieur de l'entreprise · L'avertissement est la première sanction disciplinaire — elle ne requiert pas d'audition préalable, mais doit être notifiée par écrit.</div>\n      <pre id=\"mod-avert\" class=\"mod-pre\">[En-tête de l'entreprise]\n[Ville], le [JJ/MM/AAAA]\n\nLETTRE D'AVERTISSEMENT\n\nÀ : M./Mme [Nom, Prénom]\nMatricule : [Matricule]\nPoste : [Intitulé du poste]\nService : [Nom du service]\n\nObjet : Avertissement disciplinaire\n\nMonsieur / Madame,\n\nPar la présente, nous portons à votre connaissance que vous avez commis\nle [JJ/MM/AAAA] le manquement suivant :\n\n[Décrire précisément les faits : nature, date, lieu, circonstances.\nEx. : « Vous avez été absent(e) de votre poste de travail sans autorisation\nni justificatif le [date], de [heure] à [heure], soit [durée]. »\nOU\n« Votre comportement du [date] envers [collègue / client / supérieur]\na constitué un manquement aux règles de courtoisie et de respect mutuel\ndéfinies à l'Art. […] du règlement intérieur. »]\n\nCe comportement est contraire aux obligations qui vous incombent en vertu\ndu règlement intérieur de l'entreprise et de la Loi n°90-11 du 21/04/1990.\n\nEn conséquence, nous vous adressons le présent avertissement.\nNous vous demandons instamment de ne pas réitérer ce type de comportement.\nTout manquement ultérieur de même nature entraînera des sanctions plus graves,\npouvant aller jusqu'au licenciement, conformément au barème disciplinaire\ndu règlement intérieur.\n\nLe présent avertissement sera versé à votre dossier individuel.\n\nVeuillez agréer, Monsieur / Madame, nos salutations.\n\nLe Directeur des Ressources Humaines / Le Directeur Général\n\n[Nom, Prénom]\n[Cachet de l'entreprise]\nSignature :\n\n---\nACCUSÉ DE RÉCEPTION (à retourner signé)\n\nJe soussigné(e), [Nom, Prénom], déclare avoir reçu le [JJ/MM/AAAA]\nla présente lettre d'avertissement.\n\n□ J'accepte la sanction\n□ Je conteste la sanction et souhaite formuler mes observations écrites dans un délai de [X] jours.\n\nDate : ___________    Signature : ___________</pre>\n    </div>\n\n    <!-- Mise à pied -->\n    <div class=\"panel\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 4</div><div class=\"panel-title\" style=\"margin:0\">Lettre de mise à pied disciplinaire</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-map')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Base légale : Loi n°90-11 Art. 73 et 74 · Règlement intérieur · La mise à pied suspend le contrat et entraîne une retenue de salaire proportionnelle. Elle doit être précédée d'une convocation à audition (droit de défense).</div>\n      <pre id=\"mod-map\" class=\"mod-pre\">[En-tête de l'entreprise]\n[Ville], le [JJ/MM/AAAA]\n\nMISE À PIED DISCIPLINAIRE\n\nÀ : M./Mme [Nom, Prénom]\nMatricule : [Matricule]\nPoste : [Intitulé du poste]\nService : [Nom du service]\n\nObjet : Notification de mise à pied disciplinaire\n\nMonsieur / Madame,\n\nSuite à votre audition du [JJ/MM/AAAA] en présence de [Nom du représentant\ndu salarié / délégué du personnel, ou mention « sans représentant à votre demande »],\nau cours de laquelle vous avez eu la possibilité de vous exprimer sur les faits\nqui vous sont reprochés,\n\nNous avons constaté que le [JJ/MM/AAAA], vous avez commis le fait suivant :\n\n[Description précise et factuelle du manquement : nature, date, lieu,\ncirconstances, témoins éventuels, préjudice causé.\nEx. : « Vous avez quitté votre poste de travail avant l'heure de fin de service,\nsans autorisation de votre responsable hiérarchique, à [heure], alors que\nvotre horaire de service se terminait à [heure], causant ainsi une perturbation\ndans l'organisation du service. »]\n\nVotre comportement constitue une faute disciplinaire de [2e / 3e] degré\nau sens du règlement intérieur de l'entreprise (Art. [X]).\n\nEn conséquence, nous avons décidé de vous infliger une MISE À PIED\nde [X] jours, du [JJ/MM/AAAA] au [JJ/MM/AAAA] inclus.\n\nDurant cette période :\n- Vous êtes suspendu(e) de vos fonctions ;\n- Votre salaire sera retenu au prorata des jours de mise à pied ;\n- Vous ne devez pas vous présenter sur le lieu de travail.\n\nVous serez en mesure de reprendre vos fonctions le [JJ/MM/AAAA].\n\nNous vous informons que tout nouveau manquement pourra entraîner\nune sanction plus grave, pouvant aller jusqu'au licenciement.\n\nLa présente décision sera versée à votre dossier individuel.\n\nVeuillez agréer, Monsieur / Madame, nos salutations.\n\nLe Directeur des Ressources Humaines / Le Directeur Général\n\n[Nom, Prénom]\n[Cachet de l'entreprise]\nSignature :\n\n---\nACCUSÉ DE RÉCEPTION\n\nJe soussigné(e), [Nom, Prénom], déclare avoir reçu le [JJ/MM/AAAA]\nla présente notification de mise à pied disciplinaire.\n\nDate : ___________    Signature : ___________</pre>\n    </div>\n\n    <!-- Licenciement faute grave -->\n    <div class=\"panel\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 5</div><div class=\"panel-title\" style=\"margin:0\">Lettre de licenciement pour faute grave</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-lic')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Base légale : Loi n°90-11 Art. 73, 74, 75 et 76 · <strong>Procédure obligatoire :</strong> 1) Convocation écrite à audition avec délai raisonnable → 2) Audition en présence du délégué du personnel ou représentant → 3) Notification écrite de la décision. Toute irrégularité de procédure peut entraîner l'annulation judiciaire du licenciement.</div>\n      <pre id=\"mod-lic\" class=\"mod-pre\">[En-tête de l'entreprise]\n[Ville], le [JJ/MM/AAAA]\n\nLETTRE DE LICENCIEMENT POUR FAUTE GRAVE\n\nRECOMMANDÉE AVEC ACCUSÉ DE RÉCEPTION\nOU REMISE EN MAIN PROPRE CONTRE DÉCHARGE\n\nÀ : M./Mme [Nom, Prénom]\nMatricule : [Matricule]\nPoste : [Intitulé du poste]\nService : [Nom du service]\n\nObjet : Notification de licenciement pour faute grave\n\nMonsieur / Madame,\n\nPar lettre en date du [JJ/MM/AAAA], nous vous avons convoqué(e) à un\nentretien disciplinaire qui s'est tenu le [JJ/MM/AAAA] en présence de\n[Nom du représentant du salarié / délégué du personnel, ou mention\n« vous avez renoncé à vous faire représenter »].\n\nAu cours de cet entretien, vous avez eu toute latitude pour vous expliquer\nsur les faits suivants :\n\n[Description détaillée, précise et chronologique de la (des) faute(s) grave(s) :\nEx. : « Le [date], vous avez [vol / détournement / violence physique / harcèlement /\ndivulgation d'informations confidentielles / absence injustifiée répétée après\nplusieurs avertissements / …], ce qui a causé [préjudice à l'entreprise / danger\npour la sécurité / …]. »]\n\nVos explications n'ont pas permis de modifier notre appréciation des faits.\n\nCes faits constituent une FAUTE GRAVE au sens de l'Art. 73 de la Loi n°90-11\ndu 21/04/1990 et de l'Art. [X] du règlement intérieur de l'entreprise, rendant\nimpossible le maintien de la relation de travail.\n\nEn conséquence, nous avons décidé de prononcer votre LICENCIEMENT POUR\nFAUTE GRAVE, avec effet immédiat à compter de la notification de la présente.\n\nConformément aux dispositions légales et conventionnelles applicables :\n□ Le préavis est supprimé en raison de la gravité des faits.\n□ Vous bénéficiez d'une indemnité de licenciement calculée comme suit :\n  [Indiquer le calcul selon Art. 73 et s. de la Loi n°90-11 et convention collective]\n□ Votre solde de tout compte vous sera remis dans les délais légaux.\n□ Votre certificat de travail, attestation d'affiliation CNAS et documents\n  de sortie vous seront délivrés dans les [X] jours ouvrables.\n\nNous vous informons que vous disposez des voies de recours suivantes :\n- Conciliation devant l'inspecteur du travail (Art. 96 Loi n°90-11) ;\n- Saisine de la juridiction compétente en cas d'échec de la conciliation.\n\nVeuillez agréer, Monsieur / Madame, nos salutations.\n\nLe Directeur des Ressources Humaines / Le Directeur Général\n\n[Nom, Prénom]\n[Cachet de l'entreprise]\nSignature :\n\n---\nACCUSÉ DE RÉCEPTION / DÉCHARGE\n\nJe soussigné(e), [Nom, Prénom], déclare avoir reçu le [JJ/MM/AAAA]\nla présente lettre de licenciement.\n\nDate : ___________    Signature : ___________</pre>\n    </div>\n\n  </div><!-- /tab-mod-discipline -->\n\n  <!-- ── ATTESTATIONS ──────────────────────────── -->\n  <div id=\"tab-mod-attestations\" style=\"display:none\">\n\n    <!-- Certificat de travail -->\n    <div class=\"panel\" style=\"margin-top:14px\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 6</div><div class=\"panel-title\" style=\"margin:0\">Certificat de travail</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-cert')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Base légale : Loi n°90-11 Art. 64 · Obligatoire à remettre au salarié à la rupture du contrat, quelle qu'en soit la cause. Ne peut mentionner d'appréciations subjectives.</div>\n      <pre id=\"mod-cert\" class=\"mod-pre\">[En-tête de l'entreprise]\n[Ville], le [JJ/MM/AAAA]\n\nCERTIFICAT DE TRAVAIL\n\nJe soussigné(e), [Nom, Prénom], [Qualité / Fonction], représentant(e)\nla société [Raison sociale], sise à [Adresse], NIF : [NIF],\n\nCERTIFIE\n\nque M./Mme [Nom, Prénom du salarié], né(e) le [JJ/MM/AAAA] à [Commune],\na été employé(e) dans notre établissement en qualité de [Dernier intitulé\nde poste occupé], du [JJ/MM/AAAA] au [JJ/MM/AAAA].\n\nLa présente attestation est délivrée à l'intéressé(e) pour lui servir\net valoir ce que de droit.\n\n[Ville], le [JJ/MM/AAAA]\n\n[Nom, Prénom du signataire]\n[Qualité]\n[Cachet de l'entreprise]\nSignature :</pre>\n    </div>\n\n    <!-- Attestation de travail -->\n    <div class=\"panel\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 7</div><div class=\"panel-title\" style=\"margin:0\">Attestation de travail (salarié en activité)</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-att')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Différence avec le certificat : l'attestation est délivrée au salarié <em>encore en poste</em> pour ses démarches personnelles (banque, logement, visa…). Elle ne met pas fin au contrat.</div>\n      <pre id=\"mod-att\" class=\"mod-pre\">[En-tête de l'entreprise]\n[Ville], le [JJ/MM/AAAA]\n\nATTESTATION DE TRAVAIL\n\nJe soussigné(e), [Nom, Prénom], [Qualité / Fonction], représentant(e)\nla société [Raison sociale], sise à [Adresse], NIF : [NIF],\n\nATTESTE\n\nque M./Mme [Nom, Prénom], né(e) le [JJ/MM/AAAA] à [Commune],\nest employé(e) au sein de notre entreprise en qualité de [Intitulé du poste],\ndepuis le [JJ/MM/AAAA], à la date de délivrance de la présente attestation.\n\nRémunération mensuelle brute perçue : [montant] DA\n(Option : à omettre ou à inclure selon la demande du salarié)\n\nLa présente attestation est délivrée à la demande de l'intéressé(e),\npour lui servir et valoir ce que de droit, notamment pour [préciser l'usage\nsi connu : « démarches bancaires / demande de logement / visa / … »].\n\n[Ville], le [JJ/MM/AAAA]\n\n[Nom, Prénom du signataire]\n[Qualité]\n[Cachet de l'entreprise]\nSignature :</pre>\n    </div>\n\n  </div><!-- /tab-mod-attestations -->\n\n  <!-- ── ÉVALUATION & RÈGLEMENT INTÉRIEUR ─────── -->\n  <div id=\"tab-mod-evaluation\" style=\"display:none\">\n\n    <!-- Grille d'entretien annuel -->\n    <div class=\"panel\" style=\"margin-top:14px\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 8</div><div class=\"panel-title\" style=\"margin:0\">Grille d'entretien annuel d'évaluation</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-eval')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 L'entretien annuel n'est pas imposé par la Loi n°90-11, mais constitue une bonne pratique managériale essentielle pour la GPEC, le plan de formation et la politique de rémunération.</div>\n      <pre id=\"mod-eval\" class=\"mod-pre\">GRILLE D'ENTRETIEN ANNUEL D'ÉVALUATION\n\nEntreprise : [Raison sociale]\nAnnée d'évaluation : [AAAA]\nDate de l'entretien : [JJ/MM/AAAA]\n\n─────────────────────────────────────────────────────────\nI. IDENTIFICATION\n─────────────────────────────────────────────────────────\nNom et prénom du salarié : ________________________________\nMatricule : ________________  Poste : ____________________\nService / Département : ___________________________________\nDate d'entrée dans l'entreprise : ________________________\nResponsable évaluateur : __________________________________\nPoste de l'évaluateur : __________________________________\n\n─────────────────────────────────────────────────────────\nII. BILAN DE L'ANNÉE ÉCOULÉE\n─────────────────────────────────────────────────────────\nRappel des objectifs fixés l'année précédente :\n\nN°  | Objectif                    | Résultat atteint | Appréciation (1-4)\n----|-----------------------------|-----------------|-----------------\n 1  | __________________________ | ______________ | □1 □2 □3 □4\n 2  | __________________________ | ______________ | □1 □2 □3 □4\n 3  | __________________________ | ______________ | □1 □2 □3 □4\n 4  | __________________________ | ______________ | □1 □2 □3 □4\n\nÉchelle : 1=Non atteint | 2=Partiellement atteint | 3=Atteint | 4=Dépassé\n\nCommentaires du salarié sur les résultats :\n___________________________________________________________\n___________________________________________________________\n\n─────────────────────────────────────────────────────────\nIII. ÉVALUATION DES COMPÉTENCES\n─────────────────────────────────────────────────────────\n                                          1    2    3    4\nMaîtrise technique du poste              □    □    □    □\nQualité du travail rendu                 □    □    □    □\nRespect des délais et de l'organisation  □    □    □    □\nInitiative et autonomie                  □    □    □    □\nEsprit d'équipe et coopération           □    □    □    □\nCommunication et relations de travail    □    □    □    □\nRespect des règles HSE                   □    □    □    □\nPonctualité et assiduité                 □    □    □    □\n\nNotation globale des compétences :  □1 □2 □3 □4\n\n─────────────────────────────────────────────────────────\nIV. AXES DE DÉVELOPPEMENT\n─────────────────────────────────────────────────────────\nPoints forts identifiés :\n___________________________________________________________\n\nAxes d'amélioration :\n___________________________________________________________\n\nBesoins de formation identifiés :\nFormation 1 : _________________________ Priorité : □ Haute □ Moyenne □ Faible\nFormation 2 : _________________________ Priorité : □ Haute □ Moyenne □ Faible\nFormation 3 : _________________________ Priorité : □ Haute □ Moyenne □ Faible\n\n─────────────────────────────────────────────────────────\nV. OBJECTIFS ANNÉE [AAAA+1]\n─────────────────────────────────────────────────────────\nN°  | Objectif                    | Indicateur de mesure    | Échéance\n----|-----------------------------|-----------------------|---------\n 1  | __________________________ | _____________________ | ________\n 2  | __________________________ | _____________________ | ________\n 3  | __________________________ | _____________________ | ________\n 4  | __________________________ | _____________________ | ________\n\n─────────────────────────────────────────────────────────\nVI. PERSPECTIVES D'ÉVOLUTION\n─────────────────────────────────────────────────────────\nSouhait d'évolution du salarié : ________________________\nMobilité envisagée : □ Oui  □ Non  — Vers : ______________\nPromotion envisagée pour [AAAA+1] : □ Oui  □ Non\nRévision salariale recommandée : □ Oui  □ Non — Motif : ___\n\n─────────────────────────────────────────────────────────\nVII. OBSERVATIONS LIBRES\n─────────────────────────────────────────────────────────\nObservations du salarié :\n___________________________________________________________\n___________________________________________________________\n\nObservations de l'évaluateur :\n___________________________________________________________\n___________________________________________________________\n\n─────────────────────────────────────────────────────────\nVIII. SIGNATURES\n─────────────────────────────────────────────────────────\nDate de l'entretien : [JJ/MM/AAAA]\n\nLe Salarié :                         L'Évaluateur :\nNom : _______________                Nom : _______________\nSignature :                          Signature :\n\nLe salarié reconnaît avoir été informé des résultats de son évaluation\net avoir eu la possibilité d'exprimer son point de vue.\n□ Le salarié accepte les conclusions.\n□ Le salarié émet des réserves (observations au verso).</pre>\n    </div>\n\n    <!-- Trame règlement intérieur -->\n    <div class=\"panel\">\n      <div style=\"display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:10px\">\n        <div><div class=\"panel-kicker\">Modèle 9</div><div class=\"panel-title\" style=\"margin:0\">Trame de règlement intérieur</div></div>\n        <button class=\"mod-copy-btn\" onclick=\"copyModel('mod-ri')\">📋 Copier</button>\n      </div>\n      <div class=\"panel-note\" style=\"margin-bottom:12px\">📌 Base légale : Loi n°90-11 Art. 71 · Décret exécutif n°90-227 · Obligatoire pour les entreprises de plus de 20 salariés. Doit être déposé auprès de l'inspecteur du travail et affiché dans les locaux. Le RI ne peut déroger aux dispositions légales en défaveur du salarié.</div>\n      <pre id=\"mod-ri\" class=\"mod-pre\">RÈGLEMENT INTÉRIEUR\nde la société [Raison sociale]\n[Forme juridique] — Capital : [montant] DA\nSiège social : [Adresse]\nNIF : [NIF]\n\nÉtabli conformément aux dispositions de l'Art. 71 de la Loi n°90-11 du 21/04/1990\net du Décret exécutif n°90-227 du 25/07/1990.\n\n═══════════════════════════════════════════════\nTITRE I — DISPOSITIONS GÉNÉRALES\n═══════════════════════════════════════════════\n\nArticle 1 — Champ d'application\nLe présent règlement intérieur s'applique à l'ensemble du personnel de\n[Raison sociale], quelle que soit la nature de leur contrat (CDI, CDD),\nleur catégorie professionnelle et leur lieu d'affectation.\n\nArticle 2 — Prise de connaissance\nTout salarié nouvellement embauché reçoit un exemplaire du présent règlement\nintérieur et atteste en avoir pris connaissance par sa signature au bas de son\ncontrat de travail.\n\n═══════════════════════════════════════════════\nTITRE II — ORGANISATION DU TRAVAIL\n═══════════════════════════════════════════════\n\nArticle 3 — Horaires de travail\nLa durée légale du travail est fixée à [40 ou 44] heures par semaine,\nréparties comme suit : [Ex. : du dimanche au jeudi, de 8h00 à 16h30,\navec une pause de 30 minutes].\nTout aménagement d'horaire fait l'objet d'une note de service approuvée\npar la direction.\n\nArticle 4 — Pointage et présence\nTout salarié est tenu de pointer à son arrivée et à son départ selon les\nmodalités définies par la direction [badge / registre / biométrique].\nTout pointage pour le compte d'un collègue absent est passible d'une\nsanction disciplinaire.\n\nArticle 5 — Absences et retards\n5.1 Toute absence prévisible doit être autorisée préalablement par le\nresponsable hiérarchique.\n5.2 Toute absence imprévue doit être signalée dans les 24 heures et\njustifiée dans les 48 heures (certificat médical, décision administrative…).\n5.3 Les retards répétés non justifiés constituent une faute disciplinaire.\n\nArticle 6 — Congés annuels\nLes demandes de congé annuel sont formulées par écrit, au moins [X] jours\navant la date de départ souhaitée. Le calendrier des congés est établi en\ntenant compte des besoins du service et dans le respect de l'Art. 49 et s.\nde la Loi n°90-11.\n\n═══════════════════════════════════════════════\nTITRE III — DISCIPLINE\n═══════════════════════════════════════════════\n\nArticle 7 — Principes disciplinaires\nLes sanctions disciplinaires sont graduées et proportionnelles à la gravité\ndes faits. Elles sont prononcées dans le respect des droits de la défense,\nconformément aux Art. 73 à 78 de la Loi n°90-11.\n\nArticle 8 — Échelle des sanctions\n1er degré  : Avertissement écrit\n2e degré   : Blâme\n3e degré   : Mise à pied de 1 à 3 jours\n4e degré   : Mise à pied de 4 à 8 jours\n5e degré   : Licenciement\n\nArticle 9 — Fautes graves entraînant le licenciement immédiat\nConstituent des fautes graves justifiant le licenciement sans préavis :\n- Vol, détournement ou tentative de vol au détriment de l'entreprise ;\n- Violence physique ou verbale grave à l'égard d'un collègue, supérieur ou client ;\n- Divulgation de secrets professionnels ou de données confidentielles ;\n- Falsification de documents ou de pointage ;\n- Abandon de poste caractérisé ;\n- État d'ivresse manifeste ou consommation de substances illicites sur le lieu de travail ;\n- Tout acte portant gravement atteinte aux intérêts de l'entreprise.\n\nArticle 10 — Procédure disciplinaire\nPour toute sanction du 3e degré et au-delà :\n1. Convocation écrite du salarié avec délai de préparation raisonnable ;\n2. Audition en présence du délégué du personnel ou du représentant choisi ;\n3. Rédaction d'un procès-verbal d'audition signé par les parties ;\n4. Notification écrite de la décision dans les délais légaux ;\n5. Versement au dossier individuel.\n\n═══════════════════════════════════════════════\nTITRE IV — HYGIÈNE, SÉCURITÉ ET ENVIRONNEMENT\n═══════════════════════════════════════════════\n\nArticle 11 — Obligations HSE\nTout salarié est tenu de :\n- Respecter les consignes de sécurité affichées sur les lieux de travail ;\n- Utiliser les équipements de protection individuelle (EPI) mis à disposition ;\n- Signaler immédiatement tout accident, incident ou situation dangereuse\n  au responsable HSE et/ou au CHSE ;\n- Participer aux exercices d'évacuation et aux formations sécurité obligatoires.\n\nArticle 12 — Interdictions\nIl est formellement interdit dans les locaux de l'entreprise :\n- De fumer en dehors des zones autorisées ;\n- D'introduire ou de consommer des boissons alcoolisées ou substances illicites ;\n- D'utiliser le matériel de l'entreprise à des fins personnelles sans autorisation ;\n- D'introduire des personnes étrangères à l'entreprise sans autorisation préalable.\n\n═══════════════════════════════════════════════\nTITRE V — PROTECTION DES DONNÉES ET CONFIDENTIALITÉ\n═══════════════════════════════════════════════\n\nArticle 13 — Confidentialité\nLe salarié est tenu à une obligation de discrétion absolue sur toutes les\ninformations relatives à l'activité, aux clients, aux procédés de fabrication\net aux données financières de l'entreprise, pendant la durée du contrat et après.\n\nArticle 14 — Matériel et systèmes informatiques\nLes équipements informatiques et les accès réseau sont mis à disposition\nexclusivement à des fins professionnelles. Tout usage abusif est passible\nde sanction disciplinaire.\n\n═══════════════════════════════════════════════\nTITRE VI — DISPOSITIONS FINALES\n═══════════════════════════════════════════════\n\nArticle 15 — Révision\nLe présent règlement intérieur peut être révisé à tout moment par la direction,\naprès consultation des délégués du personnel et dépôt auprès de l'inspecteur\ndu travail compétent.\n\nArticle 16 — Entrée en vigueur\nLe présent règlement intérieur entre en vigueur à compter du [JJ/MM/AAAA],\ndate de son dépôt auprès de l'Inspection du travail de [Wilaya].\n\nFait à [Ville], le [JJ/MM/AAAA]\n\nLe Directeur Général / Le Chef d'établissement\n\n[Nom, Prénom]\n[Cachet de l'entreprise]\nSignature :</pre>\n    </div>\n\n  </div><!-- /tab-mod-evaluation -->",
  "suppl": "<div class=\"panel\">\n    <div class=\"panel-kicker\">Section supplémentaire</div>\n    <div class=\"panel-title\">Référentiels techniques — Rubriques, Taux &amp; Sources</div>\n    <p class=\"panel-text\">Cette section regroupe les référentiels techniques utilisés au quotidien : catalogue des rubriques de paie avec leur statut fiscal et social, barème IRG détaillé, taux de cotisations et sources juridiques officielles. Ces outils complètent les 10 thèmes et sont indépendants des domaines RH.</p>\n  </div>\n\n  <!-- Sous-onglets -->\n  <div class=\"rh-tab-bar\" style=\"margin-bottom:0\">\n    <button class=\"rh-tab active\" onclick=\"rhShowSubTab('sub-rubriques',this)\">Rubriques de paie (47)</button>\n    <button class=\"rh-tab\" onclick=\"rhShowSubTab('sub-taux',this)\">Taux &amp; Barème IRG</button>\n    <button class=\"rh-tab\" onclick=\"rhShowSubTab('sub-sources',this)\">Sources juridiques</button>\n  </div>\n\n  <!-- Rubriques -->\n  <div id=\"tab-sub-rubriques\">\n    <div class=\"legend\">\n      <div class=\"leg\"><div class=\"leg-dot\" style=\"background:#86efac\"></div>Cotisable + Imposable</div>\n      <div class=\"leg\"><div class=\"leg-dot leg-dot-none\"></div>Ni cotisable ni imposable</div>\n      <div class=\"leg\"><div class=\"leg-dot leg-dot-imp\"></div>Non cotisable / Imposable</div>\n      <div class=\"leg\"><div class=\"leg-dot leg-dot-cot\"></div>Cotisable / Non imposable</div>\n    </div>\n    <div class=\"toolbar\">\n      <div class=\"search-wrap\">\n        <span class=\"search-icon\">🔍</span>\n        <input type=\"text\" id=\"srch\" placeholder=\"Rechercher une rubrique, une loi…\" oninput=\"rhFilterTable()\">\n      </div>\n      <span class=\"count-rhBadge\" id=\"count-info\">47 rubriques affichées</span>\n    </div>\n    <div class=\"tbl-wrap\">\n      <table class=\"main\" id=\"main-tbl\">\n        <thead>\n          <tr>\n            <th style=\"width:42px\">N°</th>\n            <th>Rubrique / Élément de salaire</th>\n            <th>Cotisable<br>CNAS</th>\n            <th>Imposable<br>IRG</th>\n            <th>Base légale</th>\n            <th>Remarques</th>\n          </tr>\n        </thead>\n        <tbody id=\"tbl-body\"></tbody>\n      </table>\n      <div class=\"no-results\" id=\"no-res\" style=\"display:none\">Aucune rubrique trouvée.</div>\n    </div>\n  </div>\n\n  <!-- Taux & Barème -->\n  <div id=\"tab-sub-taux\" style=\"display:none\">\n    <div class=\"rate-grid\">\n      <div class=\"rate-card\">\n        <h3>🛡️ Cotisations CNAS / CNR — Décret n°06-373 du 18/10/2006</h3>\n        <table class=\"rate-tbl\">\n          <tr><td>Assurances sociales</td><td>1,50 % sal. + 13,00 % pat.</td></tr>\n          <tr><td>Accidents travail / MP</td><td>— + 1,25 % pat.</td></tr>\n          <tr><td>Retraite (CNR)</td><td>6,75 % sal. + 7,50 % pat.</td></tr>\n          <tr><td>Chômage (CNAC)</td><td>0,50 % sal. + 1,00 % pat.</td></tr>\n          <tr><td>Retraite anticipée</td><td>0,25 % sal. + 0,25 % pat.</td></tr>\n          <tr><td>Fonds œuvres sociales</td><td>— + 0,50 % pat.</td></tr>\n          <tr><td><strong>TOTAL</strong></td><td><strong>9 % sal. + 25 % pat. = 34 %</strong></td></tr>\n        </table>\n      </div>\n      <div class=\"rate-card\">\n        <h3>📋 Assiette CNAS — Ord. n°95-01, Art. 1</h3>\n        <p style=\"font-size:12px;color:var(--muted);margin-bottom:8px\"><strong>Inclus</strong> dans l'assiette :</p>\n        <ul style=\"font-size:12px;color:var(--ink-soft);padding-left:16px;line-height:1.7;margin-bottom:10px\">\n          <li>Salaire de base, IEP, indemnités de poste, nuisance, nuit…</li>\n          <li>Primes mensuelles de rendement, permanence, caisse…</li>\n          <li>Heures supplémentaires, congés payés.</li>\n        </ul>\n        <p style=\"font-size:12px;color:var(--muted);margin-bottom:8px\"><strong>Exclus</strong> de l'assiette :</p>\n        <ul style=\"font-size:12px;color:var(--ink-soft);padding-left:16px;line-height:1.7\">\n          <li>Prestations à caractère familial (alloc. familiales, PSU, scolarité).</li>\n          <li>Indemnités représentatives de frais (transport, panier, téléphone).</li>\n          <li>Primes à caractère exceptionnel (innovation, expatriation).</li>\n          <li>Indemnités de résidence / isolement / zone.</li>\n          <li>Avantages en nature ≤ SNMG (cotisables à 2 % si &gt; SNMG).</li>\n        </ul>\n      </div>\n    </div>\n    <div class=\"rate-card\" style=\"margin-top:14px\">\n      <h3>📊 Barème IRG — Traitements & Salaires — Art. 104 CIDTA</h3>\n      <div style=\"overflow-x:auto\">\n        <table class=\"irg-tbl\">\n          <thead>\n            <tr>\n              <th>Fraction du revenu imposable annuel (DA)</th>\n              <th>Taux</th>\n              <th>Formule (IRG annuel brut)</th>\n              <th>Équivalent mensuel brut</th>\n            </tr>\n          </thead>\n          <tbody>\n            <tr style=\"background:var(--su-50,#f0fdf4)\">\n              <td>N'excède pas 240 000 DA</td>\n              <td><strong>0 %</strong></td>\n              <td>IRG = 0</td>\n              <td>≤ 20 000 DA/mois</td>\n            </tr>\n            <tr>\n              <td>De 240 001 DA à 480 000 DA</td>\n              <td><strong>23 %</strong></td>\n              <td>IRG = (R − 240 000) × 23 %</td>\n              <td>20 001 → 40 000 DA/mois</td>\n            </tr>\n            <tr>\n              <td>De 480 001 DA à 960 000 DA</td>\n              <td><strong>27 %</strong></td>\n              <td>IRG = 55 200 + (R − 480 000) × 27 %</td>\n              <td>40 001 → 80 000 DA/mois</td>\n            </tr>\n            <tr>\n              <td>De 960 001 DA à 1 940 000 DA</td>\n              <td><strong>30 %</strong></td>\n              <td>IRG = 184 800 + (R − 960 000) × 30 %</td>\n              <td>80 001 → 160 000 DA/mois</td>\n            </tr>\n            <tr>\n              <td>De 1 940 001 DA à 3 840 000 DA</td>\n              <td><strong>33 %</strong></td>\n              <td>IRG = 479 400 + (R − 1 940 000) × 33 %</td>\n              <td>161 668 → 320 000 DA/mois</td>\n            </tr>\n            <tr>\n              <td>Supérieure à 3 840 000 DA</td>\n              <td><strong>35 %</strong></td>\n              <td>IRG = 1 106 400 + (R − 3 840 000) × 35 %</td>\n              <td>&gt; 320 000 DA/mois</td>\n            </tr>\n          </tbody>\n        </table>\n      </div>\n      <div class=\"alert alert-blue\" style=\"margin-top:12px\">\n        <strong>Source : DGI — mfdgi.gov.dz · Art. 104 CIDTA</strong><br><br>\n        <strong>Ordre de calcul obligatoire :</strong><br>\n        1. Base cotisable CNAS = Brut − éléments non cotisables (panier, transport…)<br>\n        2. CNAS salariale = Base cotisable × 9 %<br>\n        3. Base IRG = Brut − CNAS salariale − éléments exonérés d'IRG<br>\n        4. Abattement 40 % sur base IRG (min <strong>1 000 DA/mois</strong> · max <strong>1 500 DA/mois</strong>)<br>\n        5. Application du barème progressif ci-dessus<br><br>\n        <strong>Règles spéciales (Art. 104-3 CIDTA) :</strong><br>\n        • Revenu ≤ <strong>30 000 DA/mois</strong> → Exonération totale d'IRG.<br>\n        • Revenu entre <strong>30 001 et 42 500 DA/mois</strong> → Barème + abattement 40 %, puis <strong>2e abattement dégressif</strong> :\n        <code style=\"display:block;background:var(--surface-2,#f8f9fa);border-radius:6px;padding:6px 10px;margin-top:6px;font-size:12px\">IRG net = IRG(après 1er abattement) × (93/61) − (81 213/41)</code>\n        • Travailleurs <strong>handicapés</strong> et <strong>retraités du régime général</strong> : abattement spécifique pour revenus entre 30 001 et 42 500 DA (non cumulable avec le 2e abattement).<br>\n        • Primes non mensuelles (gratification, 13e mois, bilan…) : taux libératoire <strong>10 %</strong>.\n      </div>\n    </div>\n    <div class=\"rate-card\" style=\"margin-top:14px\">\n      <h3>💵 SNMG &amp; seuils clés en vigueur (2024)</h3>\n      <table class=\"irg-tbl\">\n        <thead><tr><th>Indicateur</th><th>Montant</th><th>Référence</th></tr></thead>\n        <tbody>\n          <tr><td>SNMG mensuel</td><td><strong>24 000 DA/mois</strong></td><td>Décret n°23-411 du 28/12/2023</td></tr>\n          <tr><td>Seuil exonération IRG</td><td><strong>30 000 DA/mois</strong></td><td>Art. 104-3 CIDTA (LF 2022 art. 31)</td></tr>\n          <tr><td>Abattement IRG mensuel max</td><td><strong>1 500 DA/mois</strong></td><td>Art. 104 CIDTA</td></tr>\n          <tr><td>Abattement IRG mensuel min</td><td><strong>1 000 DA/mois</strong></td><td>Art. 104 CIDTA</td></tr>\n          <tr><td>Taux libératoire primes non mensuelles</td><td><strong>10 %</strong></td><td>Art. 104 CIDTA</td></tr>\n          <tr><td>Exonération pension retraite</td><td><strong>≤ 20 000 DA/mois</strong></td><td>Art. 68 CIDTA</td></tr>\n        </tbody>\n      </table>\n    </div>\n  </div>\n\n  <!-- Sources -->\n  <div id=\"tab-sub-sources\" style=\"display:none\">\n    <div class=\"src-grid\">\n      <div class=\"src-card\"><span class=\"src-tag\">DGI</span><div class=\"src-name\">Direction Générale des Impôts</div><div class=\"src-desc\">CIDTA — Art. 5, 66-68, 73, 104 · Barème IRG · Exonérations fiscales · Circulaire n°01/MF/DGI/2014</div><a class=\"src-url\" href=\"https://www.mfdgi.gov.dz\" target=\"_blank\">www.mfdgi.gov.dz</a></div>\n      <div class=\"src-card\"><span class=\"src-tag\">CNAS</span><div class=\"src-name\">Caisse Nationale des Assurances Sociales</div><div class=\"src-desc\">Cotisations, DAS, DAC, affiliation, AT/MP, prestations en espèces, formulaires</div><a class=\"src-url\" href=\"https://www.cnas.dz\" target=\"_blank\">www.cnas.dz</a></div>\n      <div class=\"src-card\"><span class=\"src-tag\">JORADP</span><div class=\"src-name\">Journal Officiel de la République Algérienne</div><div class=\"src-desc\">Tous textes officiels — lois, décrets, ordonnances, instructions, lois de finances</div><a class=\"src-url\" href=\"https://www.joradp.dz\" target=\"_blank\">www.joradp.dz</a></div>\n      <div class=\"src-card\"><span class=\"src-tag\">MTESS</span><div class=\"src-name\">Ministère du Travail, de l'Emploi et de la Sécurité Sociale</div><div class=\"src-desc\">Droit du travail, inspection, emploi, sécurité sociale, SNMG, conventions collectives</div><a class=\"src-url\" href=\"https://www.mtess.gov.dz\" target=\"_blank\">www.mtess.gov.dz</a></div>\n      <div class=\"src-card\"><span class=\"src-tag\">CNR</span><div class=\"src-name\">Caisse Nationale des Retraites</div><div class=\"src-desc\">Retraite, retraite anticipée, rentes, pensions de réversion — Loi n°83-12</div><a class=\"src-url\" href=\"https://www.cnr.dz\" target=\"_blank\">www.cnr.dz</a></div>\n      <div class=\"src-card\"><span class=\"src-tag\">CNAC</span><div class=\"src-name\">Caisse Nationale d'Assurance Chômage</div><div class=\"src-desc\">Cotisations chômage, dispositifs emploi, ANADE, ANGEM, FNAC, formation</div><a class=\"src-url\" href=\"https://www.cnac.dz\" target=\"_blank\">www.cnac.dz</a></div>\n      <div class=\"src-card\"><span class=\"src-tag\">ANEM</span><div class=\"src-name\">Agence Nationale de l'Emploi</div><div class=\"src-desc\">Placement, DAIP, offres d'emploi, formation, insertion professionnelle — Loi n°04-19</div><a class=\"src-url\" href=\"https://www.anem.dz\" target=\"_blank\">www.anem.dz</a></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Loi 90-11</span><div class=\"src-name\">Loi n°90-11 du 21 avril 1990</div><div class=\"src-desc\">Relations de travail : contrat, durée, rémunération, congés, discipline, rupture, syndicats</div><span class=\"src-url\">JORADP n°17 du 25/04/1990</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Lois 83-11 à 83-14</span><div class=\"src-name\">Lois de sécurité sociale (1983)</div><div class=\"src-desc\">Assurances sociales, retraite, AT/MP, obligations employeurs — fondement de la CNAS</div><span class=\"src-url\">JORADP 1983</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Loi 88-07</span><div class=\"src-name\">Loi n°88-07 du 26/01/1988</div><div class=\"src-desc\">Hygiène, sécurité et médecine du travail — obligations SST de l'employeur</div><span class=\"src-url\">JORADP n°4 du 27/01/1988</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Loi 23-02</span><div class=\"src-name\">Loi n°23-02 — Droit syndical (2023)</div><div class=\"src-desc\">Exercice du droit syndical, représentativité, protection délégués, pluralisme syndical</div><span class=\"src-url\">JORADP 2023</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">LF 2022</span><div class=\"src-name\">Loi de Finances 2022 — Art. 31</div><div class=\"src-desc\">Nouveau barème IRG 6 tranches (Art. 104 CIDTA) + exonération ≤ 30 000 DA/mois</div><span class=\"src-url\">JORADP n°100 du 31/12/2021</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">LF 2024</span><div class=\"src-name\">Loi de Finances 2024</div><div class=\"src-desc\">Exonération IRG/CNAS dispositifs emploi jeunes ANADE/ANGEM/CNAC. Maintien barème LF 2022</div><span class=\"src-url\">JORADP décembre 2023</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Ord. 95-01</span><div class=\"src-name\">Ordonnance n°95-01 du 21 janvier 1995</div><div class=\"src-desc\">Assiette de cotisation CNAS — Art. 1 : éléments inclus et exclus. Base de tous les calculs</div><span class=\"src-url\">JORADP n°5 du 25/01/1995</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Décret 06-373</span><div class=\"src-name\">Décret exécutif n°06-373 du 18/10/2006</div><div class=\"src-desc\">Répartition cotisations — taux 9 % salarié + 25 % patronal = 34 % total</div><span class=\"src-url\">JORADP n°65 du 18/10/2006</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Décret 23-411</span><div class=\"src-name\">Décret présidentiel n°23-411 du 28/12/2023</div><div class=\"src-desc\">SNMG fixé à 24 000 DA/mois — en vigueur depuis le 01/01/2024</div><span class=\"src-url\">JORADP / MTESS décembre 2023</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Décret 05-09</span><div class=\"src-name\">Décret exécutif n°05-09 du 08/01/2005</div><div class=\"src-desc\">Comités d'Hygiène, Sécurité et Environnement (CHSE) — composition, missions, fonctionnement</div><span class=\"src-url\">JORADP n°5 du 23/01/2005</span></div>\n      <div class=\"src-card\"><span class=\"src-tag\">Loi 90-02</span><div class=\"src-name\">Loi n°90-02 du 06/02/1990</div><div class=\"src-desc\">Prévention et règlement des conflits collectifs de travail — conciliation, grève, service minimum</div><span class=\"src-url\">JORADP n°6 du 07/02/1990</span></div>\n    </div>\n  </div>"
};

